(window.QUESTION_SETS = window.QUESTION_SETS || []).push({
  id: "operario_servicios",
  name: "Operario/a de Servicios",
  description: "OPE Osakidetza · 200 preguntas",
  translations: {
    eu: {
      name: "Zerbitzuetako langilea",
      description: "OPE Osakidetza · 200 galdera"
    }
  },
  questions: [
    {q:"La cocina caliente es:",o:["Es la encargada de conservar en buenas condiciones higiénicas los géneros de uso no inmediato.","Es el lugar donde se limpia y conserva la batería de cocina.","Es el lugar donde racionar ciertos platos, terminar algunos platos cocinados, confeccionar totalmente platos y guarniciones y salsas frías.","Es la encargada de transformar, por medio de calor, los alimentos crudos."],a:3,translations:{eu:{q:"Sukalde beroa honako hau da:",o:["Berehalako erabilerarako ez diren produktuak baldintza higieniko egokietan kontserbatzen dituena.","Sukaldeko bateria garbitu eta gordetzen den tokia.","Plater hotzak eta hornidurak prestatzen diren tokia.","Elikagai gordinak beroaren bidez eraldatzen dituena."]}}},
    {q:"En cocina, tendrá suelo inclinado con vertiente central a un sumidero:",o:["El economato.","La antecámara.","La cámara de refrigeración.","El fregadero."],a:2,translations:{eu:{q:"Sukaldean, zoru maldatsua eta erdian hustubidea izango duena da:",o:["Ekonomatoa.","Aurrekamara.","Hozkailu-ganbara.","Harraska-gela."]}}},
    {q:"Lugar donde se almacenan los alimentos no perecederos:",o:["Almacén.","Cuarto de verduras y frutas.","Economato.","Ninguna de las anteriores."],a:2,translations:{eu:{q:"Elikagai ez-galkorrak gordetzeko tokia:",o:["Biltegia.","Barazki eta fruta gela.","Ekonomatoa.","Aurrekoetako bat ere ez."]}}},
    {q:"La temperatura de la cámara de congelación será del orden de:",o:["0 grados centígrados.","18 grados centígrados bajo cero.","20 grados centígrados bajo cero.","12 grados centígrados bajo cero."],a:2,translations:{eu:{q:"Izozte-ganbararen tenperatura:",o:["0 ºC.","-18 ºC.","-20 ºC.","-12 ºC."]}}},
    {q:"La temperatura de la antecámara será del orden de:",o:["8 a 12 grados centígrados.","10 a 12 grados centígrados.","3 a 4 grados centígrados.","8 a 10 grados centígrados."],a:1,translations:{eu:{q:"Aurrekamararen tenperatura:",o:["8–12 ºC.","10–12 ºC.","3–4 ºC.","8–10 ºC."]}}},
    {q:"El lugar donde se limpia y conserva la batería de cocina, que posee tres pilas, grandes, profundas y fuertes, es:",o:["El cuarto de verduras y frutas.","El economato.","La plonge.","La lavandería."],a:2,translations:{eu:{q:"Hiru harraska handi eta sakon dituen bateria-garbiketa gunea:",o:["Barazki eta fruta gela.","Ekonomatoa.","Plongea.","Garbitegia."]}}},
    {q:"Recibe el nombre de “placares”:",o:["El lugar acondicionado para que la brigada de cocina se cambie y deposite sus ropas.","El lugar donde se limpia la loza, el cristal y la plata del establecimiento.","El espacio donde se limpian las planchas y rustideras de la batería de cocina.","El lugar donde se instala el friegaplatos y el lavavajillas mecánico."],a:0,translations:{eu:{q:"“Placares” izena hartzen du:",o:["Langileek arropa aldatzeko gunea.","Ontzi eta beira garbiketa gunea.","Plaken garbiketa gunea.","Ontzi-garbigailua dagoen tokia."]}}},
    {q:"El departamento que debe estar dotado de cafetera, baño maría de leche, tostadores de pan, frigorífico para zumos, mantequilla, leche, etc., pequeño fogón con plancha, pila y armario, se conoce como:",o:["Cocina de familia.","Cocina de meriendas.","Cafetería del hotel.","Ambigú."],a:2,translations:{eu:{q:"Kafegailua, esnetarako maria bainua, ogi-txigorgailuak, zukuetarako hozkailua, gurina, esnea eta abar izan behar dituen sailari, plantxa, pila eta armairua dituen sutegi txikiari, nola esaten zaio?",o:["Familia-sukaldea.","Askari-sukaldea.","Hoteleko kafetegia.","Ambigua."]}}},
    {q:"Se emplea para la conservación de alimentos crudos, y también de géneros cocinados. Su temperatura será de 1 a 2 grados centígrados aproximadamente.",o:["Antecámara.","Cámara de congelación.","Abatidor de temperatura.","Cámara de refrigeración."],a:3,translations:{eu:{q:"Elikagai gordinak zein kozinatuak 1–2 ºC-ko tenperatura inguruan kontserbatzeko erabiltzen dena.",o:["Aurrekamara.","Izozte-ganbara.","Eransgailua.","Hozkailu-ganbara."]}}},
    {q:"Las grandes cámaras frigoríficas más completas, comprenden:",o:["Antecámara, cámara de refrigeración y cámara de congelación.","Antecámara, cámara de refrigeración y abatidor de temperatura.","Sorbetera, cámara de refrigeración y cámara de congelación.","Ninguna de las anteriores."],a:0,translations:{eu:{q:"Hozkailu ganbara handiek barne hartzen dute:",o:["Aurrekamara, hozkailua eta izozte-ganbara.","Aurrekamara, hozkailua eta eransgailua.","Sorbete-makina eta hozkailua.","Aurrekoetako bat ere ez."]}}},
    {q:"Los fogones según sus características de acoplamiento podrán ser:",o:["Murales, centrales, transportables, integrales o acoplables.","Murales, centrales, plegables, integrales o por elementos.","Transportables, centrales, plegables, integrales o acoplables.","Murales, centrales, transportables, integrales o plegables."],a:0,translations:{eu:{q:"Sukalde-suak akoplamenduaren arabera:",o:["Hormakoak, zentralak, eramangarriak, integralak edo akoplatuak.","Hormakoak, zentralak, tolesgarriak, integralak edo elementuzkoak.","Eramangarriak, zentralak, tolesgarriak, integralak edo akoplatuak.","Hormakoak, zentralak, eramangarriak, integralak edo tolesgarriak."]}}},
    {q:"Señala la respuesta INCORRECTA, la cocina de familia.",o:["Estará dedicada exclusivamente a confeccionar la comida del personal.","Tiene como objetivo evitar la interferencia con la cocina de clientes.","Deberá estar situada en un lugar que domine la totalidad de la cocina y para una mejor visión formada por cristaleras.","Será, en sí, una cocina completa."],a:2,translations:{eu:{q:"Familia-sukaldeari buruz OKERRA dena:",o:["Langileentzako bazkaria egiteko izango da soilik.","Bezeroen sukaldetik bereizia.","Kristalez osatutako ikuspegi nagusia duena.","Berez, sukalde oso bat izango da."]}}},
    {q:"Señala la respuesta CORRECTA:",o:["El gas butano es más puro y gasifica mejor que el gas propano.","El gas propano es más puro y gasifica mejor que el gas butano.","El gas butano y propano son igual de puros.","El gas propano y butano gasifican igual."],a:1,translations:{eu:{q:"Erantzun ZUZENA gasari buruz:",o:["Butanoa propanoa baino garbiagoa da eta hobeto gasifikatzen du.","Propanoa butanoa baino garbiagoa da eta hobeto gasifikatzen du.","Biak berdinak dira.","Biak berdin gasifikatzen dira."]}}},
    {q:"En el gas propano, la mala combustión se identifica:",o:["Por convertir la llama en amarillenta, en vez de rojiza.","Por convertir la llama en rojiza, en vez de azulada.","Por convertir la llama en azulada, en vez de rojiza.","Por convertir la llama en rojiza, en vez de amarillenta."],a:1,translations:{eu:{q:"Propanoaren errekuntza txarra:",o:["Sugarra horixka bihurtzen da gorriaren ordez.","Sugarra gorrixka bihurtzen da urdinaren ordez.","Sugarra urdin bihurtzen da gorriaren ordez.","Sugarra gorrixka bihurtzen da horixkaren ordez."]}}},
    {q:"¿Cuál es la situación en el local de cocina de la salamandra?",o:["Partida del asador.","Cuarto frío.","Partida de carnes.","Partida del entradero o pescadero."],a:3,translations:{eu:{q:"Non egoten da kokatuta salamandra sukaldean?",o:["Erretegiaren partida.","Gela hotzean.","Haragi-partidan.","Arrain partidan."]}}},
    {q:"El tamaño de la cubeta de las freidoras:",o:["Es de 4 hasta 10 litros.","Es de 4 hasta 50 litros.","Es de 4 hasta 100 litros.","Es de 4 hasta 200 litros."],a:2,translations:{eu:{q:"Frijigailuaren edukiera:",o:["4–10 litro.","4–50 litro.","4–100 litro.","4–200 litro."]}}},
    {q:"El tipo de horno más usado es:",o:["El eléctrico.","El de gas propano.","El de leña.","El de gas-oil."],a:0,translations:{eu:{q:"Gehien erabiltzen den labe mota:",o:["Elektrikoa.","Propanoa.","Egurrezkoa.","Gasoliozkoa."]}}},
    {q:"¿Cuál de los siguientes debe situarse como medianera entre la cocina y el paso al comedor?",o:["Placar.","Prusiana.","Mesa caliente.","Plonge."],a:2,translations:{eu:{q:"Hauetako zein egon behar luke kokatuta sukaldearen eta jantokiaren sarreraren artean:",o:["Plakarra.","Armairu beroa.","Mahai beroa.","Plongea."]}}},
    {q:"¿Cuál es el generador de calor que se emplea para freír a la llamada “gran fritura” alimentos de distinta cualidad de sabor y clase, en gran cantidad, con poco ennegrecimiento de la grasa y perfecta regulación de calor?",o:["Parrilla.","Plancha parrilla.","Freidora.","Sartén abatible."],a:2,translations:{eu:{q:"Zein bero-sorgailu erabiltzen da \"frijitze handia\" deritzonean frijitzeko mota eta zapore desberdineko elikagaiak, kantitate handian, koipea gutxi belzten dutenak eta beroa ezin hobeto erregulatzen dutenak?",o:["Parrilla.","Plantxa parrilla.","Frijigailua.","Zartagin eroria."]}}},
    {q:"Los tipos de marmitas y olla a presión según el elemento de calentamiento empleado son:",o:["Vapor, gas propano y electricidad.","Electricidad únicamente.","Vapor, gas y vapor, gas directo y electricidad.","Vapor con gas, gas azul y electricidad."],a:2,translations:{eu:{q:"Hauek dira marmita eta presio-eltze motak, beroketa-elementuaren arabera:",o:["Lurruna, propano gasa eta elektrizitatea.","Elektrizitatea bakarrik.","Lurruna, gasa eta lurruna, zuzeneko gasa eta elektrizitatea.","Lurruna gasarekin, gas urdinarekin eta elektrizitatearekin."]}}},
    {q:"Los recipientes generadores de calor, con posibilidad de vaciado rápido por basculación, adecuados para elaborar salteados, estofados, arroces, fritos con poco aceite, etc., con placa cerrada o cubierta, son:",o:["Baño María.","Freidora a presión.","Sartén abatible.","Sartén volteable."],a:2,translations:{eu:{q:"Hauek dira beroa sortzen duten ontziak, baskulazio bidez azkar husteko aukera dutenak, salteatuak, erregosiak, arrozak, olio gutxirekin frijituak, etab. egiteko egokiak, plaka itxi edo estalia dutenak:",o:["Maria bainua.","Presiopeko frijigailua.","Zartagin eraisgarria.","Zartagin iraulgarria."]}}},
    {q:"Utensilio contenedor de agua caliente dentro del cual se sitúan los recipientes contenedores de alimentos para conservarlos calientes por un espacio de tiempo determinado.",o:["Baño caliente.","Roner.","Sous vide.","Ninguna de las anteriores."],a:3,translations:{eu:{q:"Bainu maria da:",o:["Ur berozko ontzia.","Ronerra.","Sous vide.","Aurrekoetako bat ere ez."]}}},
    {q:"La misión de la cámara de congelación es conservar géneros:",o:["Hasta 3 meses.","Más de 6 meses.","Hasta 6 meses.","Hasta 12 meses."],a:2,translations:{eu:{q:"Izozte-ganbarak kontserbatzen du:",o:["3 hilabete arte.","6 hilabete baino gehiago.","6 hilabete arte.","12 hilabete arte."]}}},
    {q:"Los fogones centrales (señala la opción INCORRECTA):",o:["Están construidos para instalar retirados de las paredes.","Se requieren conductos de instalación aérea o por el suelo.","Son los usados en los grandes establecimientos por permitir el agrupamiento de las partidas.","Tienen sus hornos y estufas en un solo frente, que es el de titulación de trabajo."],a:3,translations:{eu:{q:"Sukalde zentralari buruz OKERRA:",o:["Hormetatik aldenduta instalatzeko diseinatuta dago.","Instalazio-hodi bereziak behar ditu.","Establezimendu handietan erabiltzen da.","Beren labeak eta berogailuak fronte bakar batean ditu, hau da, lan-titulazioan."]}}},
    {q:"Los tipos de \"baño maría\" (señala la opción INCORRECTA):",o:["Placa de bordes altos con agua.","Fijo.","Mural.","Transportable."],a:2,translations:{eu:{q:"Mari bainu motetan OKERRA:",o:["Ur-plaka ertze altuekin.","Finkoa.","Hormakoa.","Eramangarria."]}}},
    {q:"La ventilación de la cocina será por medio de:",o:["Ventanales de salida a nivel bajo.","Ventanales de entrada a nivel más alto.","Ventanales de salida a nivel alto.","Ventanales de entrada y salida a nivel medio."],a:2,translations:{eu:{q:"Nola aireztatuko da sukaldea?",o:["Beheko mailako irteerako leihateak.","Goiko mailan sartzeko leihateak.","Goiko mailako irteerako leihateak.","Sarrerako eta irteerako leihateak maila ertainean."]}}},
    {q:"La ubicación de la cocina:",o:["Estará situada en la misma planta que los comedores principales.","Estará alejada de terrazas y comedores para evitar olores.","Para evitar que la comida se enfríe, se emplearán mantas isotérmicas.","Deberá estar alejada de la zona de llegada de mercancías para evitar contaminaciones."],a:0,translations:{eu:{q:"Sukaldearen kokapena:",o:["Jantokiaren solairu berean.","Terrazetatik urrun.","Janaria ez hozteko asmoarekin, manta isotermikoak erabiliko dira.","Merkantziak iristen diren eremutik urrun egon beharko du, kutsadurak saihesteko."]}}},
    {q:"Los materiales adecuados para la construcción de las cocinas como revestimiento de paredes, suelos y techos:",o:["En los suelos ha de buscarse material que permita el fácil deslizamiento.","Para el techo se emplea el encalado o revestimiento de yeso o pintura gris.","En las paredes han de emplearse materiales de fácil limpieza e inalterables al calor.","Ninguna de las respuestas anteriores es correcta."],a:2,translations:{eu:{q:"Sukaldeak eraikitzeko material egokiak, hala nola hormak, zoruak eta sabaiak estaltzeko:",o:["Lurrean, erraz irristatzeko moduko materiala bilatu behar da.","Sabaian, kareztatzea edo igeltsuz edo pintura grisezko estaltzea erabiltzen da.","Hormetan, erraz garbitzen diren materialak erabili behar dira, beroaren aurrean aldaezinak direnak.","Aurreko erantzun guztiak okerrak dira."]}}},
    {q:"El despacho del jefe:",o:["Debe estar alejado de la cocina para que no haya ruidos.","Dispondrá de teléfono, control de micrófonos y mesa de despacho.","Es imprescindible en todos los establecimientos, sea cual sea su tamaño.","Es el lugar donde se controlan el peso, el rendimiento y la calidad de los artículos alimenticios."],a:1,translations:{eu:{q:"Sukalde-buruaren bulegoa:",o:["Sukaldetik urrun egon behar du zaratarik egon ez dadin.","Telefonoa, mikrofonoen kontrola eta bulegoko mahaia izango ditu.","Ezinbestekoa da establezimendu guztietan, tamaina edozein dela ere.","Elikadura-gaien pisua, errendimendua eta kalitatea kontrolatzen diren tokia da."]}}},
    {q:"Los gases más usados en la generación de frío en principio fueron:",o:["Cloruro de metilo y gas carbónico.","Gas cianhídrico y el amoníaco.","El sulfuro y el amoníaco.","Ninguna de las anteriores."],a:2,translations:{eu:{q:"Hasiera batean hotzaren sorreran erabiltzen ziren gasak ziren:",o:["Metil kloruroa eta CO2.","Gas zianhidrikoa eta amoniakoa.","Sulfuroa eta amoniakoa.","Aurrekoetako bat ere ez."]}}},
    {q:"Los materiales que se utilizan principalmente para la fabricación del colador chino, son:",o:["Hierro estañado o aluminio.","Hierro estañado o acero inoxidable.","Cobre o acero inoxidable.","Aluminio anodizado o acero inoxidable."],a:1,translations:{eu:{q:"Txino-iragazkiaren materiala:",o:["Burdina edo aluminioa.","Burdina edo altzairu herdoilgaitza.","Kobrea edo altzairu herdoilgaitza.","Aluminio anodizatua edo altzairu herdoilgaitza."]}}},
    {q:"El material de fabricación del mortero o almirez será:",o:["Madera.","Acero inoxidable.","Poliestireno.","Mármol."],a:3,translations:{eu:{q:"Morteroa edo almirezea fabrikatzeko materiala hau izango da:",o:["Zura.","Altzairu herdoilgaitza.","Poliestirenoa.","Marmola."]}}},
    {q:"Para toda clase de fritos y géneros a la “gran fritura” como croquetas, gambas orly, soldaditos de pavía, etc. se utiliza:",o:["La salamandra.","La carmela.","La sauté.","El sartén escurridor o fritura."],a:3,translations:{eu:{q:"Mota guztietako frijitu eta generoetarako, \"frijitze handian\", hala nola kroketak, ganba orlyak, zoladurako soldadutxoak, etab., honako hau erabiltzen da:",o:["Salamandra.","Carmela.","Sautéa.","Zartagin frijitzailea edo frijitua."]}}},
    {q:"Se emplean para medir líquidos:",o:["Las medidas de capacidad.","Caudalímetro.","Vaso medidor.","Balanza."],a:0,translations:{eu:{q:"Likidoak neurtzeko:",o:["Edukiera-neurgailuak.","Emari-neurgailua.","Neurketa-edalontzia.","Balantza."]}}},
    {q:"Se emplea para majar y machacar elementos de condimentación:",o:["Colador cónico perforado o “chino”.","Batidora de mano.","Pasapurés de mano.","Mortero o almirez."],a:3,translations:{eu:{q:"Kondimentuak txikitzeko edo xehetzeko erabiltzen da:",o:["Txino-iragazkia.","Eskuko irabiagailua.","Pasapurea.","Morteroa edo almirria."]}}},
    {q:"El utensilio, de hierro estañado, utilizado para tamizar purés, cremas y salsas, es:",o:["Cedazo.","Pasapurés.","Tamiz.","Colador."],a:1,translations:{eu:{q:"Pureak iragazteko tresna:",o:["Zedazoa.","Pasapurea.","Bahea.","Iragazkia."]}}},
    {q:"Son tipos de cuchillos:",o:["De golpe, de medio golpe, cebollero y puntilla.","De golpe, cebollero, chuletero y puntilla.","De golpe, de medio golpe, descorazonador y deshuesador.","Cebollero, tronchante, puntilla y jamonero."],a:0,translations:{eu:{q:"Labana motak dira:",o:["Kolpekoa, kolpe-erdikoa, tipuleroa eta puntilla.","Kolpekoa, tipuleroa, txuletarakoa eta puntilla.","Kolpekoa, kolpe-erdikoa, hezur-gabetzailea eta abar.","Tipuleroa, tronchantea, puntilla eta urdaiazpiko-labana."]}}},
    {q:"Cuchillo que se emplea para cortar hortalizas, pescados, carnes, etc. de dimensiones entre 37,5 y 42 cm. Se trata de:",o:["Cuchillo de medio golpe.","Puntilla.","Cuchillo cebollero.","Cuchillo tranchelar."],a:2,translations:{eu:{q:"Barazkiak, arrainak, haragiak eta abar mozteko erabiltzen den aiztoa. 37,5 eta 42 cm bitarteko neurriak ditu. Honako hauek dira:",o:["Kolpe-erdikoa.","Puntilla.","Tipuleroa.","Trantxelatzeko aiztoa."]}}},
    {q:"Se emplea para cortar grandes piezas con huesos muy tiernos, inclusive.",o:["Macheta.","Medio golpe.","Cebollero.","Ninguna de las anteriores."],a:1,translations:{eu:{q:"Hezur bigunak dituzten haragi zati handiak mozteko erabiltzen den aiztoa:",o:["Matxeta.","Kolpe-erdikoa.","Tipuleroa.","Aurrekoetako bat ere ez."]}}},
    {q:"Se emplea para pasar y colar caldos y cremas, y también salsas.",o:["Colador “chino”.","Pasapuré.","Tamizador.","Estameña."],a:0,translations:{eu:{q:"Saldak, kremak eta saltsak iragazteko eta iragazteko erabiltzen da:",o:["Iragazki \"txinatarra\".","Pasapuré.","Bahea.","Estameña."]}}},
    {q:"En cocina, para tornear utilizaremos preferentemente:",o:["Un cuchillo de medio golpe.","Un cuchillo cebollero.","Una puntilla.","Un trinchante."],a:2,translations:{eu:{q:"Sukaldean, torneatzeko normalean erabiltzen da:",o:["Kolpe-erdikoa.","Tipuleroa.","Puntilla.","Trintxantea."]}}},
    {q:"Las aplicaciones de la balanza son:",o:["Pesar hasta un determinado número de kilos (de 6 a 10).","Pesar hasta un determinado número de kilos (de 1 a 2).","Pesar hasta un determinado número de kilos (de 4 a 12).","Pesar hasta un determinado número de kilos (de 6 a 12)."],a:3,translations:{eu:{q:"Hauek dira balantzaren aplikazioak:",o:["Kilo kopuru jakin bat pisatzea (6–10 kg).","Kilo kopuru jakin bat pisatzea (1–2 kg).","Kilo kopuru jakin bat pisatzea (4–12 kg).","Kilo kopuru jakin bat pisatzea (6–12 kg)."]}}},
    {q:"Se emplea para cortar huesos:",o:["Jamonero.","Trinchante.","Macheta.","Puntilla."],a:2,translations:{eu:{q:"Hezurrak mozteko erabiltzen da:",o:["Urdaiazpiko-ganibeta.","Trintxantea.","Matxeta.","Puntilla."]}}},
    {q:"El recipiente que se emplea para la elaboración de caldos y fondos y que, en algunos casos, sirve para hervidos se denomina:",o:["Cazo alto.","Sauté.","Rondón.","Marmita con tapa."],a:3,translations:{eu:{q:"Nola esaten zaio saldak eta hondoak egiteko erabiltzen den ontziari?",o:["Lapiko altua.","Sautéa.","Rondoia.","Marmita estalkiarekin."]}}},
    {q:"Un cuchillo jamonero mide:",o:["40 cm.","44 cm.","48 cm.","52 cm."],a:1,translations:{eu:{q:"Urdaiazpiko-ganibetaren luzera:",o:["40 cm.","44 cm.","48 cm.","52 cm."]}}},
    {q:"La capacidad de la marmita con tapa será de:",o:["De 15 a 100 litros.","De 12 a 170 litros.","De 10 a 150 litros.","De 20 a 160 litros."],a:1,translations:{eu:{q:"Estalkidun marmitaren edukiera:",o:["15–100 l.","12–170 l.","10–150 l.","20–160 l."]}}},
    {q:"En la cocina caliente, las mesas de trabajo irán paralelas a los fogones, con una separación mínima de:",o:["1 m.","1,10 m.","1,20 m.","1,30 m."],a:2,translations:{eu:{q:"Sukalde beroan, mahaiak sutegiekiko paraleloak izango dira, eta gutxieneko tartea hau izango da:",o:["1 m.","1,10 m.","1,20 m.","1,30 m."]}}},
    {q:"¿De qué material suelen estar fabricadas las medidas de capacidad?",o:["De plástico y de acero inoxidable.","De hojalata, acero inoxidable y aluminio.","De plástico, aluminio y acero estañado.","De hojalata, acero inoxidable y plástico."],a:3,translations:{eu:{q:"Zer materialez fabrikatuta egoten dira edukiera-neurriak?",o:["Plastikoa eta altzairua.","Lata, altzairua eta aluminioa.","Plastikoa eta aluminioa.","Lata, altzairua eta plastikoa."]}}},
    {q:"Se usa para trinchar jamón serrano y otras piezas similares:",o:["Trinchante o tranchelar.","Jamonero.","Deshuesador.","Cebollero."],a:1,translations:{eu:{q:"Urdaiazpikoa zatitzeko:",o:["Trintxantea.","Urdaiazpiko-ganibeta.","Hezurgabetzailea.","Tipuleroa."]}}},
    {q:"Muebles situados dentro de la cocina caliente o de sus departamentos, empleados en la conservación por refrigeración a corto plazo de géneros de uso inmediato o constante:",o:["Antecámara.","Cámaras frigoríficas.","Armarios frigoríficos.","Timbres."],a:2,translations:{eu:{q:"Sukalde beroaren edo bere sailen barruan dauden altzariak, berehala edo etengabe erabiltzen diren jeneroak epe laburreko hozte bidez kontserbatzeko erabiltzen direnak:",o:["Aurrekamara.","Hotz-ganbara.","Hotz-armairua.","Tinbreak."]}}},
    {q:"El diámetro del colador chino oscila entre:",o:["20-23 cm.","20-25 cm.","18-22 cm.","10-20 cm."],a:0,translations:{eu:{q:"Txino-iragazkiaren diametroa:",o:["20–23 cm.","20–25 cm.","18–22 cm.","10–20 cm."]}}},
    {q:"Lugar de almacenaje de artículos poco perecederos, como fiambres, conservas y escabeches:",o:["Cámara de refrigeración.","Antecámara.","Cuarto frío.","Armarios frigoríficos."],a:1,translations:{eu:{q:"Oso galkorrak ez diren gaiak biltegiratzeko lekua, hala nola fianbreak, kontserbak eta eskabetxeak:",o:["Hozkailu-ganbara.","Aurrekamara.","Gela hotza.","Hotz-armairua."]}}},
    {q:"El material empleado para la fabricación de la sartén es:",o:["Hierro fundido.","Hierro negro.","Hierro estañado.","Teflón."],a:1,translations:{eu:{q:"Zartagina fabrikatzeko erabiltzen den materiala:",o:["Burdinurtua.","Burdin beltza.","Burdin eztainuztua.","Tefloia."]}}},
    {q:"¿Qué diámetro suele tener el mortero grande?",o:["14,5 cm.","26 cm.","30 cm.","25,5 cm."],a:2,translations:{eu:{q:"Mortero handiaren diametroa:",o:["14,5 cm.","26 cm.","30 cm.","25,5 cm."]}}},
    {q:"Se establece para las mesas de trabajo en lo que se refiere a la amplitud, que cada puesto de trabajo necesita:",o:["1,20 metros de largo por 0,50 de ancho.","1,20 metros de largo por 0,70 de ancho.","1,30 metros de largo por 0,50 de ancho.","1,30 metros de largo por 0,70 de ancho."],a:1,translations:{eu:{q:"Lanpostu bakoitzak behar duen zabaltasunari dagokionez, lan-mahaietarako ezartzen da:",o:["1,20 metro luze eta 0,50 metro zabal.","1,20 metro luze eta 0,70 metro zabal.","1,30 metro luze eta 0,50 metro zabal.","1,30 metro luze eta 0,70 metro zabal."]}}},
    {q:"La capacidad de las cámaras de congelación, marcada en litros o metros cúbicos, será:",o:["Adecuada a las necesidades de almacenamiento.","La mayor capacidad posible para cubrir imprevistos.","De 50 metros cúbicos.","Es indiferente."],a:0,translations:{eu:{q:"Izozte-ganberen edukiera, litro edo metro kubikotan markatuta, honako hau izango da:",o:["Biltegiratze-beharretara egokitua.","Ezustekoak estaltzeko ahalik eta gaitasun handiena.","50 metro kubikokoa.","Berdin dio."]}}},
    {q:"El material empleado para la fabricación del rallador manual es:",o:["Acero inoxidable.","Hierro y acero inoxidable.","Hojalata y hierro.","Hojalata."],a:3,translations:{eu:{q:"Eskuzko birringailua fabrikatzeko material hau erabiltzen da:",o:["Altzairu herdoilgaitza.","Burdina eta altzairu herdoilgaitza.","Latorria eta burdina.","Latorria."]}}},
    {q:"La misión del cuarto frío es:",o:["Conservar grandes piezas de carne y también géneros cocinados.","Limpiar y racionar los géneros en crudo.","Conservar géneros, por medio de la congelación a largo plazo.","Lugar donde se limpia y conserva la batería de cocina."],a:1,translations:{eu:{q:"Gela hotzaren eginkizuna hau da:",o:["Haragizko pieza handiak eta prestatutako generoak kontserbatzea.","Elikagaiak gordinik garbitzea eta errazionatzea.","Generoak kontserbatzea, epe luzerako izoztearen bidez.","Sukaldeko bateria garbitzeko eta gordetzeko lekua."]}}},
    {q:"Respecto al comedor del personal de cocina (señala la INCORRECTA):",o:["Suele estar anexo a la cocina.","Puede tener dos o tres mesas.","Debe ser un lugar agradable por su temperatura, aspecto y sencilla comodidad.","Estará dotada de cafetera y baño maría, pequeño fogón con plancha, pila y armario."],a:3,translations:{eu:{q:"Sukaldeko langileen jantokiari dagokionez (adierazi OKERRA):",o:["Sukaldearen ondoan egoten da.","Bi edo hiru mahai izan ditzake.","Leku atsegina izan behar du tenperaturagatik, itxuragatik eta erosotasun errazagatik.","Kafe-makina eta maria bainua izango ditu, baita plantxa, pila eta armairua ere."]}}},
    {q:"Su misión es conservar, cocinar y distribuir los alimentos.",o:["La cocina.","La mesa caliente.","La cocina caliente.","La cafetería del hotel."],a:0,translations:{eu:{q:"Bere eginkizuna elikagaiak kontserbatzea, prestatzea eta banatzea da:",o:["Sukaldea.","Mahai beroa.","Sukalde beroa.","Hoteleko kafetegia."]}}},
    {q:"Entre las instalaciones necesarias en el cuarto frío están (SEÑALE LA INCORRECTA):",o:["Grandes pilas con agua fría.","Tajos o pilones.","Altavoz que permita escuchar las comandas.","Cajones basculantes para legumbres secas."],a:3,translations:{eu:{q:"Gela hotzean behar diren instalazioen artean daude (adierazi zein EZ den zuzena):",o:["Pila handiak ur hotzarekin.","Langak edo piloiak.","Komandak entzun ahal izateko bozgorailua.","Lekale lehorrentzako tiradera kulunkariak."]}}},
    {q:"La temperatura de la mesa caliente será:",o:["Menor de 100 º C.","Entre 20 y 50 ºC.","Entre 70 y 120 ºC.","Entre 40 y 60 ºC."],a:0,translations:{eu:{q:"Mahai beroaren tenperatura hau izango da:",o:["100º C baino gutxiago.","20 eta 50 ºC artean.","70 eta 120 ºC artean.","40 eta 60 ºC artean."]}}},
    {q:"La capacidad máxima de una cacerola será de:",o:["25 litros.","32 litros.","23 litros.","28 litros"],a:2,translations:{eu:{q:"Lapiko baten gehieneko edukiera hau izango da:",o:["25 litro.","32 litro.","23 litro.","28 litro."]}}},
    {q:"Se usa para rallar géneros tales como: quesos duros, nuez moscada, cáscara de limón, etc.",o:["Rallador eléctrico.","Rallador microplane.","Rallador manual.","Rallador “chino”."],a:2,translations:{eu:{q:"Gazta gogorrak, intxaur muskatua, limoi oskola eta abar birrintzeko erabiltzen da.",o:["Birringailu elektrikoa.","Mikroplane-birringailua.","Eskuzko birringailua.","Txinatar birringailua."]}}},
    {q:"Utensilio contenedor de agua caliente dentro del cual se sitúan los recipientes contenedores de alimentos para conservarlos calientes por espacio de un tiempo determinado:",o:["Marmita con tapa.","Sartén basculante.","Mesa caliente.","Baño María."],a:3,translations:{eu:{q:"Ur beroko edukiontzia. Barruan elikagai-edukiontziak daude, denbora jakin batean bero-bero edukitzeko.",o:["Marmita estalkiarekin.","Zartagin baskulagarria.","Mahai beroa.","Maria bainua."]}}},
    {q:"Fuera de la hora del “servicio” puede usarse como lugar de trabajo y estufa fermentadora.",o:["Sartén abatible.","Sartén basculante.","Mesa caliente.","Mesa de trabajo."],a:2,translations:{eu:{q:"\"Zerbitzutik\" kanpo, lantoki eta hartzidura-berogailu gisa erabil daiteke.",o:["Zartagin eroria.","Zartagin baskulagarria.","Mahai beroa.","Lan-mahaia."]}}},
    {q:"Señala el requisito INNECESARIO en un buen programa de limpieza hospitalaria:",o:["Buen personal.","Equipo adecuado.","Flexibilidad de horarios.","Procedimientos de limpieza modernos."],a:2,translations:{eu:{q:"Aukera hauetatik zein EZ da beharrezkoa ospitale-garbiketarako programa on baterako?",o:["Lantalde ona.","Ekipamendu egokia.","Ordu-malgutasuna.","Garbiketa-prozedura modernoak."]}}},
    {q:"Señala la respuesta CORRECTA:",o:["Se deben utilizar mopas de algodón de 16 onzas (unos 453 gramos) para las habitaciones con enfermos.","Se deben utilizar mopas de algodón de 24 onzas (unos 680 gramos) en las zonas públicas.","Se deben utilizar mopas de 12 pulgadas (unos 30 cm) para zonas más estrechas.","a) b) y c) son correctas."],a:3,translations:{eu:{q:"Adierazi erantzun ZUZENA:",o:["Kotoizko 16 ontzako (453 gramo inguru) mopak erabili behar dira gaixoak dauden geletan.","Kotoizko 24 ontzako (680 gramo inguru) mopak erabili behar dira eremu publikoetan.","12 hazbeteko (30 cm inguru) mopak erabili behar dira toki estuetan.","a) b) eta c) zuzenak dira."]}}},
    {q:"En la limpieza de ventanas, la segunda pasada debe hacerse:",o:["Empezando por la superficie seca, por la esquina derecha de la parte superior de la ventana.","Empezando por la superficie seca, por la esquina izquierda de la parte inferior de la ventana.","Empezando por la superficie seca, por la esquina izquierda de la parte superior de la ventana.","Empezando por la superficie mojada, por la esquina izquierda de la parte superior de la ventana."],a:2,translations:{eu:{q:"Leihoen garbiketan, nola egin behar da bigarren pasaldia?",o:["Lehortutako zatitik hasita, leihoaren goiko eskuineko ertzetik.","Lehortutako zatitik hasita, leihoaren beheko ezkerreko ertzetik.","Lehortutako zatitik hasita, leihoaren goiko ezkerreko ertzetik.","Zati bustitik hasita, leihoaren goiko ezkerreko ertzetik."]}}},
    {q:"En relación con la aplicación y acabado de resina en mesas (muebles):",o:["Haga una pasada, o sea, una capa.","Haga dos pasadas, o sea, dos capas.","Haga tres pasadas, o sea, tres capas.","No es recomendable su uso."],a:2,translations:{eu:{q:"Mahaietan (altzarietan) akaberan erretxina emateari dagokionez, aukera hauetatik zein da ZUZENA?",o:["Pasaldi bat eman, hau da, erretxina-geruza bat.","Bi pasaldi eman, hau da, bi erretxina-geruza.","Hiru pasaldi eman, hau da, hiru erretxina-geruza.","Ez da gomendagarria erretxina erabiltzea."]}}},
    {q:"El procedimiento de esterilización de las habitaciones hospitalarias conlleva:",o:["Esperar 24 horas después del fumigado antes de entrar en la habitación.","Esperar 12 horas después del fumigado antes de entrar en la habitación.","Esperar 1 hora después del fumigado antes de entrar en la habitación.","Esperar 30 minutos después del fumigado antes de entrar en la habitación."],a:3,translations:{eu:{q:"Ospitaleetako gelak esterilizatzeko prozedurari dagokionez, aukera hauetatik zein da ZUZENA?",o:["Gela fumigatu ondoren, 24 ordu itxaron behar da sartu aurretik.","Gela fumigatu ondoren, 12 ordu itxaron behar da sartu aurretik.","Gela fumigatu ondoren, ordubete itxaron behar da sartu aurretik.","Gela fumigatu ondoren, 30 minutu itxaron behar da sartu aurretik."]}}},
    {q:"Bacteriostático es:",o:["Cualquier agente químico que destruye las bacterias.","Cualquier agente químico que retrasa o inhibe el crecimiento de las bacterias.","Cualquier agente de índole químico.","Ninguna es correcta."],a:1,translations:{eu:{q:"Zer dira agente bakteriostatikoak?",o:["Bakterioak deuseztatzen dituen edozein agente kimiko.","Bakterioen hazkundea atzeratzen edo galarazten duen edozein agente kimiko.","Edozein agente kimiko.","Aurreko bat bera ere ez da zuzena."]}}},
    {q:"Proceso mediante el cual se destruyen todos los organismos tanto patógenos como no patógenos incluyendo esporas:",o:["Desinfección.","Aniquilación.","Esterilización.","Desgerminación."],a:2,translations:{eu:{q:"Zer izen du organismo guztiak, patogenoak nahiz patogenoak ez direnak, baita esporak ere, deuseztatzeko prozesuak?",o:["Desinfekzio.","Deuseztapen.","Esterilizazio.","Desgerminatze."]}}},
    {q:"Señala la CORRECTA:",o:["Para poder ocuparse de la limpieza de los quirófanos, es necesario un cierto conocimiento de microbiología y electricidad, así como un considerable dominio de los procedimientos de sanificación.","Para poder ocuparse de la limpieza de los quirófanos, no es necesario un cierto conocimiento de microbiología y electricidad.","Para poder ocuparse de la limpieza de los quirófanos, es necesario un cierto conocimiento de microbiología, electricidad e inmunología.","Ninguna es correcta."],a:0,translations:{eu:{q:"Adierazi erantzun ZUZENA:",o:["Operazio-geletako garbiketa egiteko, beharrezkoa da nolabaiteko ezagutza edukitzea mikrobiologiari eta elektrizitateari buruz, baita sanifikazio-prozedurak oso ondo menderatzea ere.","Operazio-geletako garbiketa egiteko, EZ da beharrezkoa nolabaiteko ezagutza edukitzea mikrobiologiari eta elektrizitateari buruz.","Operazio-geletako garbiketa egiteko, beharrezkoa nolabaiteko ezagutza edukitzea mikrobiologiari, elektrizitateari eta inmunologiari buruz.","Aurreko bat bera ere ez da zuzena."]}}},
    {q:"La técnica de limpieza básica empleada actualmente en los quirófanos es:",o:["Mopa y doble cubo.","Limpieza con el lavapavimentos.","Limpieza spray.","a) b) y c) son correctas."],a:3,translations:{eu:{q:"Gaur egun, operazio-geletan zer oinarrizko garbiketa-teknika erabiltzen da?",o:["Mopa eta balde bikoitza.","Zorua garbitzeko makina.","Garbiketa espraiarekin.","a) b) eta c) zuzenak dira."]}}},
    {q:"La limpieza de los pavimentos es una operación muy importante ya que:",o:["Elimina grandes concentraciones de polvo e impide la acumulación de materiales no conductores.","Elimina grandes concentraciones de bacterias e impide la acumulación de materiales conductores.","Elimina grandes concentraciones de polvo, impide la acumulación de materiales conductores y evita que el personal resbale.","Elimina grandes concentraciones de bacterias, impide la acumulación de materiales no conductores y evita que el personal resbale."],a:3,translations:{eu:{q:"Zoruen garbiketa oso garrantzitsua da; izan ere...",o:["Hauts-kontzentrazio handiak kentzen dira eta material ez-eroaleen metaketa eragozten da.","Bakterio-kontzentrazio handiak kentzen dira eta material eroaleen metaketa eragozten da.","Hauts-kontzentrazio handiak kentzen dira, material eroaleen metaketa eragozten da eta langileak ez dira irristatuko.","Bakterio-kontzentrazio handiak kentzen dira eta material ez-eroaleen metaketa eragozten da eta langileak ez dira irristatuko."]}}},
    {q:"El recipiente de plástico que contiene una bolsa plástica color gris que sobresale 5 o 10 centímetros del borde del bote y se utiliza para depositar los desechos ordinarios no recuperables es de color:",o:["Rojo.","Amarillo.","Verde.","Gris."],a:2,translations:{eu:{q:"Zer koloretakoa da berreskuratzen ez diren hondakin arruntetarako plastikozko ontzia, zeinak potearen ertzetik 5-10 cm ateratzen den plastikozko poltsa gris bat duen?",o:["Gorria.","Horia.","Berdea.","Grisa."]}}},
    {q:"El término “coeficiente del fenol”, aplicado a un producto, es:",o:["La medida del poder exterminador de este producto, comparado con el del ácido carbónico puro.","El número que indica si el producto es ácido, alcalino o neutro.","La medida del poder limpiador de este producto, comparado con el del ácido carbónico puro.","Ninguna de las respuestas anteriores es correcta."],a:0,translations:{eu:{q:"Produktu bati buruz ari garela, zer esan nahi du «fenol-koefiziente» adierazpideak?",o:["Produktu horrek duen deuseztatze-ahalmena, azido karboniko puruaren ahalmenarekin alderatuta.","Produktu azidoa, alkalinoa edo neutroa dela adierazten duen zenbakia.","Produktu horrek duen garbitze-ahalmena, azido karboniko puruaren ahalmenarekin alderatuta.","Aurreko bat bera ere ez da zuzena."]}}},
    {q:"El pH de un producto es:",o:["Un número que indica el grado de densidad del material.","Un número que indica si el material es ácido, alcalino o neutro.","Un número que indica el grado de humedad del material.","Ninguna de las respuestas anteriores es correcta."],a:1,translations:{eu:{q:"Zer da produktu baten pH-a?",o:["Materialaren dentsitate-gradua.","Materiala azidoa, alkalinoa edo neutroa den adierazten duen zenbakia.","Materialaren hezetasun-gradua.","Aurreko bat bera ere ez da zuzena."]}}},
    {q:"Señala la respuesta INCORRECTA:",o:["La función de la limpieza y el mantenimiento no debe interferir con la función principal del cuidado de los enfermos.","El departamento de limpieza y mantenimiento de un hospital es el centro alrededor del cual se desarrollan toda clase de actividades que implican todo un sinfín de responsabilidades.","Es necesario que los alrededores del hospital ofrezcan un aspecto atractivo.","Los procedimientos básicos de limpieza en ningún caso pueden ser modificados."],a:3,translations:{eu:{q:"Adierazi zein EZ den zuzena:",o:["Garbiketak eta mantentze-lanek ezin dute oztopatu zeregin nagusia, hau da, gaixoen zainketa.","Ospitaleko garbiketa eta mantentze departamentuaren inguruan era guztietako jarduerak egiten dira, askotariko erantzukizunak dituztenak.","Beharrezkoa da ospitalearen inguruek itxura erakargarria izatea.","Ezin dira inolaz ere aldatu oinarrizko garbiketa-prozedurak."]}}},
    {q:"El objetivo del fregado con mopa y doble cubo es:",o:["Conseguir una limpieza más esmerada, más higiénica y de más belleza ambiental.","Dejar en el suelo el detergente germicida el tiempo suficiente para que mate las bacterias.","Eliminar todo el polvo del pavimento.","Quitar toda suciedad del suelo, antes de aplicar el nuevo acabado al suelo."],a:0,translations:{eu:{q:"Zein da moparekin eta ontzi bikoitzarekin garbitzearen helburua?",o:["Garbiketa sakonagoa eta higienikoagoa izatea eta ingurumen-edertasun handiagokoa lortzea.","Detergente germizida bakterioak hil arte uztea zoruan.","Zoruko hauts guztia kentzea.","Zoruko zikinkeria guztia kentzea, zoruari akabera berria eman aurretik."]}}},
    {q:"Señala la respuesta que NO es correcta:",o:["En el proceso de esterilización de habitaciones hay que ponerse uniforme apropiado, mascarilla y guantes de goma.","En el proceso de esterilización de habitaciones hay que sellar la habitación.","En el proceso de esterilización de habitaciones hay que airear la habitación.","En el proceso de esterilización de habitaciones hay que fumigar al menos durante 15 minutos."],a:3,translations:{eu:{q:"Adierazi zein EZ den zuzena:",o:["Gelen esterilizatzeko prozesuan, jantzi behar dira uniforme egokia, maskara eta gomazko eskularruak.","Gelak esterilizatzeko prozesuan, gela zigilatu behar da.","Gelak esterilizatzeko prozesuan. gela aireztatu behar da.","Gelen esterilizatzeko prozesuan, gutxienez 15 minutuz fumigatu behar da."]}}},
    {q:"El objetivo de la limpieza y desinfección de una habitación ocupada aislada es:",o:["Ofrecer una habitación limpia al nuevo paciente que debe ocuparla.","Ofrecer una habitación limpia y atractiva al nuevo paciente que debe ocuparla.","Ofrecer una habitación limpia, higiénica y atractiva usando las más modernas técnicas de asepsia.","Ofrecer una habitación atractiva al nuevo paciente que debe ocuparla."],a:2,translations:{eu:{q:"Zein da okupatutako gela isolatu bat garbitzearen eta desinfektatzearen helburua?",o:["Hartu behar duen paziente berriari gela garbia ematea.","Hartu behar duen paziente berriari gela garbia eta erakargarria ematea.","Gela garbia, higienikoa eta erakargarria ematea, asepsia-teknika modernoenei esker.","Hartu behar duen paziente berriari gela erakargarria ematea."]}}},
    {q:"Los antisépticos son:",o:["Agentes o sustancias fuertes, por lo general de índole químico, que no entran en contacto con el tejido viviente, sino que se aplican a objetos inanimados, destruyendo los microorganismos patógenos.","Soluciones más débiles porque hay peligro de lesionar tejidos ya que se aplican sobre el cuerpo humano. Con actividad microbiana suficiente para interferir el desarrollo de la infección.","Cualquier agente químico que retrasa o inhibe el crecimiento de bacterias.","Cualquier agente químico que destruye bacterias."],a:1,translations:{eu:{q:"Zer dira antiseptikoak?",o:["Agente edo substantzia gogorrak, oro har, kimikoak, ez direnak ehun bizidunetan jartzen, baizik eta objektu bizigabeetan, mikroorganismo patogenoak suntsitzeko.","Soluzio ahulagoak ehunak kaltetzeko arriskua baitago, giza gorputzetan aplikatzen baitira, infekzio baten bilakaeran eragiteko nahikoa jarduera mikrobiano dutenetan.","Bakterioen hazkundea atzeratzen edo galarazten duen edozein agente kimiko.","Bakterioak suntsitzen dituen edozein agente kimiko."]}}},
    {q:"Son agentes o sustancias fuertes, por lo general de índole químico, que no entran en contacto con el tejido viviente, sino que se aplican a objetos inanimados, destruyendo los microorganismos patógenos:",o:["Bactericidas.","Antisépticos.","Desinfectantes.","Esterilizantes."],a:2,translations:{eu:{q:"Zer izen dute mikroorganismo patogenoak suntsitzeko objektu bizigabeetan, baina ez ehun bizidunetan, jartzen diren agente edo substantzia gogorrek, oro har, kimikoek?",o:["Bakterizidak.","Antiseptikoak.","Desinfektatzaileak.","Esterilizatzaileak."]}}},
    {q:"Señala la respuesta que NO es correcta:",o:["La limpieza de los pavimentos es una operación muy importante ya que elimina grandes concentraciones de bacterias.","La limpieza de los pavimentos es una operación muy importante ya que impide la acumulación de materiales no conductores.","La limpieza de los pavimentos es una operación muy importante ya que evita que el personal resbale.","Muchos pavimentos de los quirófanos son no conductores para impedir la formación de electricidad estática."],a:3,translations:{eu:{q:"Adierazi zein EZ den zuzena:",o:["Zoruak garbitzea oso ekintza garrantzitsua da, bakterio-kontzentrazio handiak deuseztatzen baititu.","Zoruak garbitzea oso ekintza garrantzitsua da, material ez-eroaleak metatzea eragozten baitu.","Zoruak garbitzea oso ekintza garrantzitsua da, langileek irrist egin ez dezaten.","Ebakuntza-geletako zoru asko ez-eroaleak dira, ez dadin elektrizitate estatikoa sortu."]}}},
    {q:"Respecto al manejo de basuras hospitalarias:",o:["No deben permanecer recipientes que contengan basuras en áreas de mucha circulación de manera que causen problemas estéticos entre otros.","La separación de la basura debe hacerse en destino.","La basura debe apretarse en las bolsas plásticas con el fin de ocupar menos espacio y evitar accidentes.","La basura debe vaciarse de un recipiente a otro."],a:0,translations:{eu:{q:"Ospitaleko zaborren kudeaketari dagokionez:",o:["Zirkulazio handiko eremuetan ez da zaborrontzirik utziko, besteak beste, arazo estetikoak ekiditeko.","Zaborra helmugan bereizi behar da.","Zaborra plastikozko poltsetan estutu behar da, leku gutxiago har dezan eta istripuak saihesteko.","Zaborra ontzi batetik bestera hustu behar da."]}}},
    {q:"Señala la respuesta que NO es correcta. Entre los efectos nocivos que más comúnmente encontramos originados por los deshechos tenemos:",o:["Los contaminantes.","Los tóxicos.","Los patógenos.","Los alérgicos."],a:3,translations:{eu:{q:"Hondakinen eragin kaltegarri hauetatik zein EZ da zuzena?",o:["Kutsatzailea.","Toxikoa.","Patogenoa.","Alergikoa."]}}},
    {q:"Señala la respuesta que NO es correcta:",o:["La recolección de basura debe efectuarse en horas que no coincidan con las de mayor tránsito (comida, visitas, etc.).","La basura seca es aquella que proviene de la limpieza diaria, y también se incluye a los residuos sólidos que son recuperables para terceros.","La basura húmeda es aquella que proviene del servicio de alimentación, cirugía, etc.","La recolección de basura en cada área del hospital debe tener una frecuencia mínima de una vez cada dos días."],a:3,translations:{eu:{q:"Adierazi zein EZ den zuzena:",o:["Zaborraren bilketa-orduek ezin dute bat etorri joan-etorri handieneko orduekin (bazkaria, bisitak, etab.).","Zabor lehorra eguneroko garbiketan sortzen da, eta barne hartzen ditu hirugarrenentzat berrerabilgarriak izan daitezkeen hondakin solidoak.","Zabor hezearen jatorriak elikadura-zerbitzua eta kirurgia-zerbitzua dira, besteak beste.","Ospitaleko eremu guztietan gutxienez bi egunean behin bildu behar da zaborra."]}}},
    {q:"En el procedimiento de quitar el polvo con mopas en zonas públicas, pasillos y vestíbulos, utilizaremos:",o:["Mopas de impregnación de 1,20 m.","Mopas de impregnación de 1 m.","Mopas de impregnación de 80 cm.","Mopas de impregnación de 30 cm."],a:0,translations:{eu:{q:"Gune publikoetan, korridoreetan eta atarietan hautsa mopekin kentzeko prozeduran, zer erabiliko dugu?",o:["1,20 m-ko mopa bustia.","1 m-ko mopa bustia.","80 cm-ko mopa bustia.","30 cm-ko mopa bustia."]}}},
    {q:"En el procedimiento de quitar el polvo con mopas en habitaciones con pacientes y áreas congestionadas, remplazaremos el cabezal de la mopa:",o:["Máximo tres veces al día.","Al cambiar de estancia.","Cuando la suciedad ya no pueda ser quitada o vea que está demasiado sucia.","a) b) y c) son correctas."],a:2,translations:{eu:{q:"Pazienteak dauden geletan eta eremu jendetsuetan hautsa mopekin kentzean, noiz aldatuko da moparen burua?",o:["Egunean hiru aldiz gehienez.","Gelaz aldatzean.","Ez duenean garbitzen edo zikinegi dagoenean.","a) b) eta c) zuzenak dira."]}}},
    {q:"En el procedimiento de “Aplicación del acabado de los suelos”:",o:["Deje que se seque la primera capa durante unos 5 minutos.","Deje que se seque la primera capa durante unos 20 minutos.","Deje que se seque la primera capa durante unos 60 minutos.","Deje que se seque la primera capa durante al menos 24 horas."],a:1,translations:{eu:{q:"Lurzoruen akabera aplikatzeko:",o:["Lehen geruza lehortzen utzi behar da 5 minutuz.","Lehen geruza lehortzen utzi behar da 20 minutuz.","Lehen geruza lehortzen utzi behar da 60 minutuz.","Lehen geruza lehortzen utzi behar da gutxienez 24 orduz."]}}},
    {q:"En la limpieza de una habitación que está desocupada:",o:["Empiece a fregar partiendo de la puerta y siga trabajando a lo largo de la habitación.","Inspeccione y quite las telarañas.","Se debe fregar la habitación y el cuarto de baño todos los días, aunque siga desocupada.","Ninguna es correcta."],a:1,translations:{eu:{q:"Hutsik dagoen gela bat garbitzean:",o:["Gelako zorua garbitzen atetik abiatuta hasi behar da.","Gela arakatu eta armiarma-sareak kendu.","Gela eta bainugela egunero garbitu behar dira, nahiz eta hutsik egon.","Aurreko erantzun guztiak okerrak dira."]}}},
    {q:"La limpieza y desinfección recurrente en áreas críticas se hace:",o:["Diariamente y se repite 2 o más veces al día según las condiciones de cada área.","Periódicamente cada 2 días.","Periódicamente cada 7 días.","Ninguna es correcta."],a:0,translations:{eu:{q:"Nola egiten da eremu kritikoetako garbiketa eta desinfekzio errepikatua?",o:["Egunero eta egunean bitan edo gehiagotan errepikatzen da, eremu bakoitzaren baldintzen arabera.","Aldizka, 2 egunean behin.","Aldizka, 7 egunean behin.","Aurreko erantzun guztiak okerrak dira."]}}},
    {q:"Señala la respuesta que NO es correcta:",o:["La limpieza diaria de la sala de reanimación incluirá quitar el polvo de los muebles con un detergente germicida.","La limpieza diaria de la sala de reanimación incluirá limpiar en seco con una mopa todo el pavimento.","Una limpieza completa de la sala de reanimación debería realizarse, al menos, mensualmente.","La limpieza completa de la sala de reanimación incluye el lavado de las paredes y los puntos de luz."],a:1,translations:{eu:{q:"Adierazi zein EZ den zuzena:",o:["Bizkorketa-gelaren eguneroko garbiketan, altzariei hautsa kenduko zaie detergente germizida batekin.","Bizkorketa-gelaren eguneroko garbiketan, zorua mopa lehor batez pasatuko da, besteak beste.","Hilean behin gutxienez bizkorketa-gelaren garbiketa osoa egingo da.","Bizkorketa-gela goitik behera garbitzen denean paretak eta argi-puntuak ere garbitu behar dira."]}}},
    {q:"Para depositar los residuos sólidos patógenos y residuos sólidos tóxicos utilizaremos:",o:["Bolsa plástica color negro.","Recipiente color rojo.","Recipiente plástico color verde.","Recipiente color naranja."],a:0,translations:{eu:{q:"Zer erabiliko dugu hondakin solido patogenoak eta hondakin solido toxikoak botatzeko?",o:["Plastikozko poltsa beltzak.","Ontzi gorriak.","Plastikozko ontzi berdeak.","Laranja koloreko ontziak."]}}},
    {q:"Cuando un producto tiene un coeficiente de fenol del 2, quiere decir que es aproximadamente:",o:["Unas 2 veces más efectivo que el ácido carbónico.","Unas 20 veces más efectivo que el ácido carbónico.","Unas 40 veces más efectivo que el ácido carbónico.","Unas 80 veces más efectivo que el ácido carbónico."],a:2,translations:{eu:{q:"Produktu baten fenol-koefizientea 2koa denean, zer esan nahi du gutxi gorabehera?",o:["Azido karbonikoa baino 2 aldiz efektiboagoa dela.","Azido karbonikoa baino 20 aldiz efektiboagoa dela.","Azido karbonikoa baino 40 aldiz efektiboagoa dela.","Azido karbonikoa baino 80 aldiz efektiboagoa dela."]}}},
    {q:"El agente “chelating” es un producto limpiador que:",o:["En un detergente incrementa la efectividad del producto.","Aporta espuma jabonosa.","Reduce la espuma jabonosa.","Al combinarse con materiales solubles los convierte en insolubles."],a:0,translations:{eu:{q:"Nolakoa da “chelating” agentea?",o:["Produktuaren eraginkortasuna handitzen duen detergentea da.","Xaboi-aparra ematen du.","Xaboi-aparra gutxitzen du.","Material disolbagarriekin konbinatzean, disolbaezin bihurtzen ditu."]}}},
    {q:"Utensilios y equipo necesario para el abrillantado de suelos:",o:["Máquina fregadora provista de cepillos abrillantadores.","Discos de lana de acero o discos abrillantadores sintéticos.","Mopas de fregar de 24 onzas (unos 680 gramos) para las áreas públicas.","a) b) y c) son correctas."],a:3,translations:{eu:{q:"Zer tresna erabiltzen da zoruak distirarazteko?",o:["Eskuila distira-emaileak dituen garbiketa-makina.","Altzairuzko artilezko diskoak edo disko distira-emaile sintetikoak.","Gune publikoak garbitzeko 24 ontzako mopak (680 gramo inguru).","a) b) eta c) zuzenak dira."]}}},
    {q:"Para quitar el polvo con mopas en habitaciones con pacientes y áreas congestionadas se utilizan mopas de impregnación:",o:["De 1,20 m.","De 45-50 cm.","De 80-85 cm.","De 1 m."],a:1,translations:{eu:{q:"Pazienteak dituzten geletan eta jendea pilatzen den eremuetan hautsa mopekin kentzeko, inpregnatze-mopak erabiltzen dira:",o:["1,20 m-koak.","45-50 cm-koak.","80-85 cm-koak.","1 m-koak."]}}},
    {q:"El objetivo del fregado con mopas esterilizadas es:",o:["Dejar en el suelo detergente germicida el tiempo suficiente para que mate las bacterias.","Conseguir una limpieza más esmerada, más higiénica y de más belleza ambiental.","Quitar los desperdicios, el polvo y la suciedad del suelo.","Que el ambiente esté limpio, higiénico y atractivo."],a:0,translations:{eu:{q:"Zer da mopa esterilizatuekin garbitzearen helburua?",o:["Zoruan detergente germizida zabaltzea bakterioak hiltzeko nahikoa den denboran.","Garbiketa sakonagoa, higienikoagoa eta inguru-edertasun handiagokoa izatea.","Zoruko hondakinak, hautsa eta zikinkeria kentzea.","Giroa garbia, higienikoa eta erakargarria izatea."]}}},
    {q:"¿Qué paso NO se realiza en el fregado de mopa y doble cubo?",o:["Quitar el polvo.","Aplicar la disolución del fregado a la mopa.","Recoger el agua sucia.","Pasar la máquina abrillantadora."],a:3,translations:{eu:{q:"Zer pauso EZ da egin behar mopaz eta kubo bikoitzaz garbitzean?",o:["Hautsa kentzea.","Garbitzeko disoluzioa mopan aplikatzea.","Ur zikina jasotzea.","Distiragailua pasatzea."]}}},
    {q:"Señala la respuesta INCORRECTA. En el lavado de paredes:",o:["Una parte importante es la técnica de asepsia en la incomunicación de la habitación.","En el depósito de la máquina se echa el detergente germicida y medio litro de agua.","Al preparar la maquinaria se bombea a mano la bomba hasta llegar a la presión recomendada.","Las marcas y manchas difíciles se deben quitar rascando con la almohadilla abrasiva."],a:1,translations:{eu:{q:"Adierazi zein den erantzun OKERRA. Hormen garbiketa:",o:["Zati garrantzitsu bat da asepsia-teknika gelako inkomunikazioan.","Makinaren gordailuan detergente germizida eta litro erdi ur botatzen dira.","Makineria prestatzean, ponpa eskuz ponpatzen da, gomendatutako presiora iritsi arte.","Arrasto eta orban zailak kentzeko kuxin urratzailearekin arraspatu behar da."]}}},
    {q:"¿Cuál de las siguientes acciones NO se debe realizar en el mantenimiento diario de habitaciones de descanso?",o:["Desinfectar la taza del wáter y los urinarios.","Fregar las instalaciones con un paño mojado.","Vaciar los recipientes de desechos.","Cambiar las cortinas y los cortinajes."],a:3,translations:{eu:{q:"Atseden-gelen eguneroko mantentze-lanetan, ekintza hauetako zein EZ da egin behar?",o:["Komunontzia eta pixalekuak desinfektatzea.","Instalazioak oihal busti batekin garbitzea.","Zaborrontziak hustea.","Errezelak eta gortinak aldatzea."]}}},
    {q:"Proceso que destruye la mayor parte de los microorganismos, pero no todas las formas:",o:["Esterilización.","Desgerminación.","Desinfección.","Limpieza."],a:2,translations:{eu:{q:"Mikroorganismo gehienak, baina EZ guztiak, suntsitzen dituen prozesua:",o:["Esterilizazioa.","Desgerminazioa.","Desinfekzioa.","Garbiketa."]}}},
    {q:"Señala la respuesta INCORRECTA:",o:["Las bacterias se reproducen aproximadamente cada 50 segundos.","Las bacterias son células vivientes.","La suciedad es una fuente excelente de alimento para las bacterias.","La supervivencia de las bacterias está ligada a la disponibilidad de alimento."],a:0,translations:{eu:{q:"Adierazi zein den erantzun OKERRA:",o:["Bakterioak 50 segundoan behin ugaltzen dira, gutxi gorabehera.","Bakterioak zelula bizidunak dira.","Zikinkeria elikagai-iturri bikaina da bakterioentzat.","Bakterioen biziraupena elikagaien eskuragarritasunarekin lotuta dago."]}}},
    {q:"Señala la respuesta INCORRECTA. En la limpieza postoperatoria:",o:["Se lavan los cubos con jabón y germicida.","Las esponjas y la ropa sucia de sangre se colocan en contenedores separados.","La ropa blanca y verde se guardan en el mismo saco.","Se deben mover los muebles a una parte de la estancia."],a:2,translations:{eu:{q:"Adierazi zein den erantzun OKERRA. Ebakuntza ondoko garbiketa:",o:["Ontziak xaboiarekin eta germizidarekin garbitzen dira.","Belakiak eta odolaz zikindutako arropa edukiontzi bereizietan jartzen dira.","Arropa zuria eta berdea zaku berean gordetzen dira.","Altzariak gelaren parte batera mugitu behar dira."]}}},
    {q:"La limpieza general de los quirófanos se realiza:",o:["Una vez acabadas todas las operaciones programadas.","Hacia las cinco de la tarde.","Entre operación y operación.","Por la mañana, justo antes de empezar con las operaciones."],a:0,translations:{eu:{q:"Noiz egiten da ebakuntza-gelen garbiketa orokorra?",o:["Programatutako ebakuntza guztiak amaitu ondoren.","Arratsaldeko bostak aldera.","Ebakuntza eta ebakuntza artean.","Goizetan, ebakuntzak hasi aurretik."]}}},
    {q:"Señala la afirmación INCORRECTA:",o:["Las ruedas de los muebles del quirófano se deben limpiar siempre muy bien para eliminar todos los residuos.","Si se olvida un objeto en la sala operatoria las bacterias podrían difundirse rápidamente.","Siempre se debe aplicar el sellador en los pavimentos conductores de los quirófanos.","Los pavimentos de los quirófanos son conductores, para impedir la formación de electricidad estática."],a:2,translations:{eu:{q:"Adierazi esaldi OKERRA:",o:["Ebakuntza-gelako altzarien gurpilak oso ondo garbitu behar dira beti, hondakin guztiak ezabatzeko.","Ebakuntza-gelan objekturen bat ahaztuz gero, bakterioak azkar zabal litezke.","Ebakuntza-geletako zoladura eroaleetan zigilatzailea aplikatu behar da beti.","Ebakuntza-geletako zoruak eroaleak dira, ez dadin elektrizitate estatikoa sortu."]}}},
    {q:"Para la limpieza y desinfección de los equipos del área de endoscopia se debe utilizar diariamente hipoclorito de sodio en:",o:["500 ppm.","50 ppm.","200 ppm.","100 ppm."],a:2,translations:{eu:{q:"Endoskopia-eremuko ekipoak garbitzeko eta desinfektatzeko, egunero sodio- hipokloritoa erabili behar da:",o:["500 ppm.","50 ppm.","200 ppm.","100 ppm."]}}},
    {q:"Son los desechos procedentes de la elaboración de materiales y suministros propios del hospital:",o:["Desechos industriales.","Desechos contaminantes.","Desechos orgánicos.","Desechos orgánicos humanos."],a:0,translations:{eu:{q:"Ospitaleko berezko materialak eta hornidurak egitean sortzen diren hondakinak dira:",o:["Hondakin industrialak.","Hondakin kutsatzaileak.","Hondakin organikoak.","Giza hondakin organikoak."]}}},
    {q:"Señala la respuesta INCORRECTA. Para el correcto mantenimiento de la mopa se debe:",o:["Enjuagar la mopa después de cada sesión de trabajo.","Retorcer la mopa para escurrir.","Utilizar los colgadores de mopas.","Utilizar el tamaño de mopa apropiado para cada exprimidor."],a:1,translations:{eu:{q:"Adierazi zein den erantzun OKERRA. Mopa behar bezala mantentzeko, hau egin behar da:",o:["Lan-saio bakoitzaren ondoren, mopa uretan pasatu.","Mopa xukatzeko bihurritu.","Mopa-esekigailuak erabili.","Xukaderaren araberako mopa-tamaina egokia erabili."]}}},
    {q:"Identifica la respuesta CORRECTA sobre el factor pH:",o:["El pH del 1 al 6 es ácido y del 8 al 14 es alcalino.","Un valor de pH 8 es neutro.","Los ácidos son más fuertes cuando el número es más grande, es decir, del 7 al 14.","Las respuestas b) y c) son correctas."],a:0,translations:{eu:{q:"Identifikatu pH faktoreari buruzko erantzun ZUZENA:",o:["1 eta 6ra bitarteko pH-a azidoa da, eta 8 eta 14 bitartekoa, berriz, alkalinoa.","8ko pH-balioa neutroa da.","Zenbat eta zenbaki altuagoa, orduan eta indartsuagoa da azidoa (hau da, 7tik 14ra).","b) eta c) erantzunak zuzenak dira."]}}},
    {q:"En la limpieza de los zócalos, en la aplicación del disolvente:",o:["Se utiliza una brocha de unos 5 cm y se deja reposar durante 5 minutos.","Se utiliza un rodillo de 10 cm y se deja reposar durante 15 minutos.","Se utiliza una brocha de unos 15 cm y se deja reposar durante 30 minutos.","Se utiliza una brocha de unos 5 cm y se deja reposar durante 15 minutos."],a:0,translations:{eu:{q:"Zokaloak garbitzeko disolbatzailea aplikatzean:",o:["5 cm inguruko brotxa erabiltzen da eta 5 minutuz uzten da.","10 cm-ko arrabola erabiltzen da eta 15 minutuz uzten da.","15 cm inguruko brotxa erabiltzen da eta 30 minutuz uzten da.","5 cm inguruko brotxa erabiltzen da eta 15 minutuz uzten da."]}}},
    {q:"Señala la opción CORRECTA. Para la limpieza diaria de los quirófanos debe:",o:["Lavarse las manos y las uñas con jabón quirúrgico durante 3 minutos.","Ponerse un uniforme de quirófano limpio.","Recoger los residuos y limpiar la zona operatoria con un spray desinfectante.","a) b) y c) son correctas."],a:3,translations:{eu:{q:"Adierazi aukera ZUZENA. Ebakuntza-gelak egunero garbitzeko:",o:["Eskuak eta azazkalak xaboi kirurgikoz garbitu behar dira 3 minutuz.","Ebakuntza-gelako uniforme garbi bat jantzi behar da.","Hondakinak bildu behar dira, eta ebakuntza-eremua garbitu, spray desinfektatzaile batekin.","a) b) eta c) zuzenak dira."]}}},
    {q:"En la sala de reanimación se debe limpiar el polvo de los muebles y de los aparatos en húmedo con detergente germicida:",o:["Todos los días.","Semanalmente.","Mensualmente.","Cada 2 días."],a:0,translations:{eu:{q:"Bizkorketa-gelan altzarietako eta gailuetako hautsa zapi heze eta detergente germizidarekin garbitu behar da:",o:["Egunero.","Astean behin.","Hilean behin.","2 egunean behin."]}}},
    {q:"El objetivo de la renovación de suelos es:",o:["Proteger varios tipos de superficies y mantener limpio y atractivo el suelo del hospital.","Conseguir una limpieza más esmerada, más higiénica y de más belleza ambiental.","Quitar los desperdicios, el polvo y la suciedad del suelo.","Quitar toda suciedad del suelo, la cera o acabados sintéticos antes de aplicar el nuevo acabado del suelo."],a:3,translations:{eu:{q:"Lurzoruak berritzearen helburua da:",o:["Zenbait motatako gainazalak babestea eta ospitaleko zorua garbi eta erakargarri mantentzea.","Garbiketa sakonagoa, higienikoagoa eta inguru-edertasun handiagokoa izatea.","Zoruko hondakinak, hautsa eta zikinkeria kentzea.","Zoruko zikinkeria, argizaria edo akabera sintetiko guztiak kentzea lurzoruaren akabera berria aplikatu aurretik."]}}},
    {q:"Algunos residuos pueden causar infecciones o enfermedades en animales y personas, debido a sus características, a su composición o a su utilización. ¿A qué efecto nocivo de los desechos se refiere esta frase?",o:["Efectos contaminantes.","Efectos tóxicos.","Efectos patógenos.","Plagas."],a:2,translations:{eu:{q:"«Hondakin batzuek infekzioak edo gaixotasunak eragin diezaiekete animaliei eta pertsonei, beren ezaugarriengatik, osaeragatik edo erabileragatik». Hondakinen zer eragin kaltegarriri egiten dio erreferentzia esaldi horrek?",o:["Ondorio kutsagarriei.","Efektu toxikoei.","Efektu patogenoei.","Izurriteei."]}}},
    {q:"Señala la opción CORRECTA. Los productos de higienización:",o:["Son productos que reducen el número de gérmenes o bacterias con el fin de garantizar los niveles mínimos de seguridad recomendados en la salvaguarda de la salud pública.","Son sustancias que se aplican a una superficie que se supone que puede ser infecciosa y sirven para matar las bacterias infecciosas de los objetos inanimados.","Son productos limpiadores que en un detergente incrementan la efectividad del producto.","Son productos que exterminan las bacterias, se aplican especialmente a los agentes químicos que matan a los gérmenes patógenos."],a:0,translations:{eu:{q:"Adierazi aukera ZUZENA. Higienizazio-produktuak:",o:["Germen edo bakterio kopurua murrizten duten produktuak dira, osasun publikoa babesteko gomendatutako gutxieneko segurtasun-mailak bermatzeko.","Ustez infekziosoa izan daitekeen gainazal batean aplikatzen diren substantziak dira, eta objektu bizigabeen bakterio infekziosoak hiltzeko balio dute.","Garbigarri batean produktuaren eraginkortasuna areagotzen duten produktu garbitzaileak dira.","Bakterioak akabatzen dituzten produktuak dira, bereziki germen patogenoak hiltzen dituzten agente kimikoei aplikatzen zaizkie."]}}},
    {q:"Señala la opción INCORRECTA. En la limpieza de las ventanas:",o:["La parte exterior de las ventanas es posible que necesite una disolución más concentrada.","En ventanas grandes, remoje y pase el limpiador solamente por la mitad inferior de la misma.","Empiece siempre pasando el limpiador pegado al marco de la ventana.","En las ventanas altas utilice pértigas extensibles."],a:1,translations:{eu:{q:"Adierazi esaldi OKERRA. Leihoak garbitzean:",o:["Baliteke leihoen kanpoaldeak disoluzio kontzentratuagoa behar izatea.","Leiho handietan, busti eta leiho-garbigailua pasatu beheko erditik bakarrik.","Hasi beti leihoaren markoari itsatsitako leiho-garbigailua pasatzen.","Goiko leihoetan pertika luzagarriak erabili."]}}},
    {q:"Son utensilios y equipo necesario para el abrillantado de los suelos:",o:["La máquina fregadora provista de cepillos abrillantadores.","Los discos de lana de acero o discos abrillantadores sintéticos.","El doble cubo, uno para fregar y el otro para enjuagar.","a) b) y c) son correctas."],a:3,translations:{eu:{q:"Lurzoruak distirarazteko beharrezko lanabesak eta tresneria dira:",o:["Garbitzeko makina, distira ematen duten eskuilak dituena.","Altzairuzko artilezko diskoak edo distira ematen duten disko sintetikoak.","Kubo bikoitza, bat garbitzeko eta bestea urberritzeko.","a) b) eta c) zuzenak dira."]}}},
    {q:"Señala la opción CORRECTA. La desgerminación es:",o:["Un procedimiento encaminado a disminuir el número de gérmenes en un área. Tal es el caso del lavado de las manos o el aseo de pisos.","El proceso que destruye la mayor parte de los microorganismos, pero no todas las formas.","Proceso mediante el cual se destruyen todos los organismos tanto patógenos como no patógenos incluyendo esporas.","a) b) y c) son correctas."],a:0,translations:{eu:{q:"Adierazi aukera ZUZENA. Zer da desgerminazioa?",o:["Eremu batean germen kopurua murrizteko prozedura. Adibidez, eskuak garbitzea edo zoruak garbitzea.","Mikroorganismo gehienak suntsitzen dituen prozesua, baina ez forma guztiak.","Organismo patogeno eta ez-patogeno guztiak suntsitzeko prozesua, esporak barne.","a) b) eta c) zuzenak dira."]}}},
    {q:"Señala la respuesta INCORRECTA. Pasos a realizar en la limpieza de una habitación que está ocupada por un paciente:",o:["Vaciado de los cubos de desperdicios.","Fregar la habitación y el cuarto de baño.","Fregar toda la cama, los colchones, las fundas, todos los muebles, instalaciones, y el alféizar de las ventanas.","Quitar el polvo de la habitación."],a:2,translations:{eu:{q:"Adierazi zein den erantzun OKERRA. Paziente batek okupatutako gela bat garbitzeko egin beharreko urratsak:",o:["Hondakin-ontziak hustea.","Garbitu logela eta bainugela.","Garbitu ohe osoa, koltxoiak, zorroak, altzari guztiak, instalazioak, eta leihoen leiho-ertza.","Gelako hautsa kentzea."]}}},
    {q:"Señala la respuesta INCORRECTA:",o:["La limpieza y desinfección recurrente se hace diariamente y se repite 2 o más veces al día según las condiciones de cada área.","La limpieza y desinfección terminal se hace cuando entra un paciente infectado o periódicamente cada 8 días.","En la limpieza y desinfección terminal se pretende cubrir todos los materiales, equipos y toda el área incluyendo la parte alta de las paredes y ventanas.","En la limpieza y desinfección en áreas críticas es recomendable una estricta limpieza y desinfección."],a:1,translations:{eu:{q:"Adierazi zein den erantzun OKERRA:",o:["Garbiketa eta desinfekzio errepikaria egunero egiten da, eta egunean 2 aldiz edo gehiagotan errepikatzen da, eremu bakoitzaren baldintzen arabera.","Garbiketa eta desinfekzio terminala paziente infektatu bat sartzen denean edo 8 egunetik behin egiten da.","Garbiketa eta desinfekzio terminalean, material, ekipo eta eremu osoa estali nahi da, pareten eta leihoen goiko aldea barne.","Eremu kritikoak garbitzean eta desinfektatzean, komeni da zorrotz garbitzea eta desinfektatzea."]}}},
    {q:"El departamento de Limpieza y Mantenimiento de un Hospital se responsabiliza de:",o:["Mantenimiento del edificio.","Equipo.","Dar facilidades en la limpieza del Hospital.","a) b) y c) son correctas."],a:3,translations:{eu:{q:"Ospitale bateko Garbiketa eta Mantentze Sailaren ardura da:",o:["Eraikinaren mantentze-lanak.","Ekipoa.","Ospitalea garbitzeko erraztasunak ematea.","a) b) eta c) zuzenak dira."]}}},
    {q:"Señala la respuesta INCORRECTA:",o:["Si el cuerpo del paciente está limpio los gérmenes tienen más posibilidades de penetrar en el paciente.","Si el médico tiene el uniforme limpio los gérmenes tienen menos posibilidades de penetrar en el paciente.","Cuanto más limpio esté el quirófano, menos posibilidades de infección existirán para nuestro paciente.","Las bacterias presentes en el aire pueden penetrar en el paciente y causar infecciones o enfermedades."],a:0,translations:{eu:{q:"Adierazi zein den erantzun OKERRA:",o:["Pazientearen gorputza garbi badago, germenek aukera gehiago dituzte pazientearengan sartzeko.","Medikuak uniformea garbi badu, germenek aukera gutxiago dituzte pazientearengan sartzeko.","Ebakuntza-gela zenbat eta garbiago egon, orduan eta infekzio-aukera gutxiago egongo dira gure pazientearentzat.","Airean dauden bakterioak pazientearengan sar daitezke eta infekzioak edo gaixotasunak sor ditzakete."]}}},
    {q:"La limpieza que tiene por objetivo el ofrecer un aspecto limpio, higiénico y atractivo sin molestar al paciente es:",o:["La limpieza de las habitaciones aisladas que acaban de ser desocupadas.","La limpieza de una habitación que está ocupada por un paciente.","El abrillantado de los suelos.","El fregado con mopa y doble cubo."],a:1,translations:{eu:{q:"Zer da itxura garbia, higienikoa eta erakargarria ematea helburu duen garbiketa, pazienteari enbarazurik egin gabe?",o:["Hutsik geratu berri diren gela isolatuak garbitzea.","Paziente batek okupatutako gela bat garbitzea.","Zoruak distiraraztea.","Moparekin eta kubo bikoitzarekin garbitzea."]}}},
    {q:"El objetivo de quitar el polvo con mopas es:",o:["Limpiar de una forma esmerada toda la habitación y todos los muebles antes que otro paciente la ocupe, de tal manera que ofrezca un aspecto atractivo e higiénico.","Proteger varios tipos de superficies y mantener limpio, seguro, y atractivo el suelo de todo el hospital.","Quitar los desperdicios, polvo y suciedad del suelo como tarea diaria de mantenimiento o como preparación para el fregado con mopa y cubo.","Ofrecer un aspecto limpio, higiénico y atractivo sin molestar al paciente."],a:2,translations:{eu:{q:"Zer da hautsa mopekin kentzearen helburua?",o:["Arreta handiz garbitu gela osoa eta altzari guztiak, beste paziente batek okupatu baino lehen, itxura erakargarria eta higienikoa izan dezan.","Hainbat azalera mota babestea eta ospitale osoko lurzorua garbi, seguru eta erakargarri mantentzea.","Hondakinak, hautsa eta zikinkeria kentzea eguneroko mantentze-lan gisa edo mopa eta kuboarekin garbitzeko prestaketa gisa.","Itxura garbia, higienikoa eta erakargarria eskaintzea, pazienteari enbarazurik egin gabe."]}}},
    {q:"Los recipientes destinados para depositar agujas usadas y darle su disposición final son:",o:["Recipientes de color naranja.","Recipientes plásticos de color verde.","Bolsas plásticas de color negro.","Recipientes rígidos."],a:3,translations:{eu:{q:"Orratz erabiliak uzteko eta azken xedapena emateko ontziak honako hauek dira:",o:["Laranja koloreko ontziak.","Plastikozko ontzi berdeak.","Plastikozko poltsa beltzak.","Ontzi zurrunak."]}}},
    {q:"El objetivo de la aplicación del acabado de los suelos es:",o:["Proteger varios tipos de superficies y mantener limpio, seguro y atractivo el suelo de todo el hospital.","Ofrecer una habitación limpia, higiénica y atractiva usando las más modernas técnicas de asepsia.","Limpiar de una forma esmerada toda la habitación y todos los muebles antes que otro paciente la ocupe, de tal manera que ofrezca un aspecto atractivo e higiénico.","Conseguir una limpieza más esmerada, más higiénica y de más belleza ambiental."],a:0,translations:{eu:{q:"Lurzoruen akabera aplikatzearen helburua da:",o:["Hainbat azalera mota babestea eta ospitale osoko lurzorua garbi, seguru eta erakargarri mantentzea.","Asepsia-teknikarik modernoenak erabiliz gela garbi, higieniko eta erakargarria eskaintzea.","Arreta handiz garbitu gela osoa eta altzari guztiak, beste paziente batek okupatu baino lehen, itxura erakargarria eta higienikoa izan dezan.","Garbitasun arretatsuagoa, higienikoagoa eta giro-edertasun handiagokoa lortzea."]}}},
    {q:"Tiene por objetivo el mantener el suelo limpio, seguro y atractivo:",o:["El abrillantado de los suelos.","Fregar con mopas esterilizadas.","El mantenimiento diario de habitaciones de descanso.","La desinfección de las habitaciones ocupadas aisladas."],a:0,translations:{eu:{q:"Lurzorua garbi, seguru eta erakargarri mantentzea du helburu:",o:["Zoruak distiraraztea.","Mopa esterilizatuekin garbitu.","Atseden-gelak egunero mantentzea.","Isolatutako gela okupatuak desinfektatzea."]}}},
    {q:"En un hospital general, el cambio de ropa de las camas y de los pacientes es más frecuente, pudiéndose admitir el cambio diario de la misma hasta un total de:",o:["6 kg. /lecho/día.","4 kg. /lecho/día.","2 kg. /lecho/día.","1 kg. /lecho/día."],a:1,translations:{eu:{q:"Ospitale orokor batean, oheko arropa eta pazienteen arropa sarriago aldatzen, eta horien eguneroko aldaketa onar daiteke honako neurri hauetako batean:",o:["6 kg/ohantze/egun.","4 kg/ohantze/egun","2 kg/ohantze/egun.","1 kg/ohantze/egun"]}}},
    {q:"La máquina de lavar más utilizada en la lavandería de los hospitales modernos es:",o:["Una lavadora convencional, con control manual y automático.","Una lavadora-extractora, que combina el proceso de lavado con la centrifugación o acondicionamiento.","Una lavadora de desinfección, que queda encajada entre paredes o barrera contra la contaminación.","Una lavadora continua, también llamada túnel de lavado."],a:2,translations:{eu:{q:"Zein da ospitale modernoetako ikuztegian gehien erabiltzen den garbiketa- makina?",o:["Ohiko garbigailua, eskuko kontrolarekin eta kontrol automatikoarekin.","Garbigailu-erauzgailu bat, zeinak konbinatzen baititu garbiketa-prozesua zentrifugazioarekin edo egokitzapenarekin.","Desinfektatzeko garbigailua, pareten artean edo kutsaduraren aurkako hesian sartuta geratzen dena.","Garbiketa-tunela."]}}},
    {q:"El equipamiento que se destina a secar y a planchar la ropa al mismo tiempo se denomina:",o:["Cabina.","Extractor.","Calandra.","Prensa."],a:2,translations:{eu:{q:"Nola esaten zaio arropa aldi berean lehortzen eta lisatzen duen ekipamenduari?",o:["Kabina.","Erauzgailu.","Kalandra.","Prentsa."]}}},
    {q:"Señala la CORRECTA:",o:["La centrífuga o extractora elimina hasta 60% de agua de la ropa salida de la lavadora.","Las lavadoras – extractoras requieren más espacio.","La capacidad de la lavadora continua varía de 300 a 1000 kg. de ropa seca procesada por hora.","La prensa está constituida por dos cilindros, uno fijo externo y uno giratorio interno."],a:2,translations:{eu:{q:"Adierazi erantzun ZUZENA:",o:["Zentrifugagailuak garbigailutik irteten den arroparen uraren % 60 arte kentzen du.","Garbigailu-erauzgailuek leku handiagoa hartzen dute.","Garbigailu jarraituak orduko 300 eta 1.000 kilo arropa lehor artean prozesatu ditzake..","Prentsa bi zilindroz osatuta dago: kanpoko bat finkoa eta barneko bat birakaria."]}}},
    {q:"El equipamiento destinado a pasar ropa de personal, donde se esteriliza la ropa es la:",o:["Centrífuga o extractora.","Calandra.","Plancha de vapor.","Prensa."],a:3,translations:{eu:{q:"Zer ekipamendu erabiliko da langileen arropa pasatuz esterilizatzeko?",o:["Zentrifugagailua.","Kalandra.","Lurrun-lisaburdina.","Prentsa."]}}},
    {q:"Los tejidos para la confección de la ropa más utilizados en el hospital son:",o:["Algodón y poliéster/algodón.","Algodón y viscosa.","Algodón y lino.","Algodón y poliamida."],a:0,translations:{eu:{q:"Zein dira ospitaleko arropa fabrikatzeko gehien erabiltzen diren ehunak?",o:["Kotoia eta poliesterra/kotoia.","Kotoia eta biskosa.","Kotoia eta lihoa.","Kotoia eta poliamida."]}}},
    {q:"La calidad del agua utilizada en lavandería:",o:["Es muy importante y debe cumplir, por lo menos, tres requisitos.","Es importante, debe de ser blanda.","Es indiferente, lo que importa son los productos.","No tiene importancia, depende de la máquina."],a:0,translations:{eu:{q:"Garbitegian erabilitako uraren kalitatea:",o:["Oso garrantzitsua da, eta gutxienez hiru baldintza bete behar ditu.","Garrantzitsua da, biguna izan behar da.","Ez du axola; produktuek, ordea, bai.","Ez du garrantzirik, makinaren araberakoa da."]}}},
    {q:"El vapor consumido en la lavandería para el calentamiento del agua, secadoras, calandras y prensas debe ser de:",o:["No se necesita vapor.","Vapor de baja presión.","Vapor de alta presión.","Vapor de media presión."],a:2,translations:{eu:{q:"Ura berotzeko, lehorgailuetarako, kalandretarako eta prentsetarako garbitegian kontsumitzen den lurruna nolakoa izan behar da?",o:["Ez da lurrunik behar.","Behe-presioko lurruna.","Presio handiko lurruna.","Presio ertaineko lurruna."]}}},
    {q:"En el procesamiento de la ropa hospitalaria, la que se debe introducir en los sacos de plástico autosolubles es la:",o:["Ropa reciclable.","Ropa sucia.","Ropa contaminada.","Ropa esterilizada."],a:2,translations:{eu:{q:"Ospitaleko arroparen prozesamenduan, zein da plastiko autodisolbagarrizko zakuetan sartu beharrekoa?",o:["Birziklatzeko arropa.","Arropa zikina.","Arropa kutsatua.","Arropa esterilizatua."]}}},
    {q:"Los Sacos Autodisolubles:",o:["Desinfectan el agua de lavado y las aguas residuales.","Están fabricados en film opaco.","Son permeables a cualquier tipo de transpiración de gas, etc.","Son tóxicos para el organismo humano."],a:0,translations:{eu:{q:"Zaku autodisolbagarriak:",o:["Garbiketako ura eta hondakin-urak desinfektatzen dituzte.","Film opakuz eginak daude.","Gasarekiko eta abarrekiko iragazkorrak dira.","Toxikoak dira giza organismoarentzat."]}}},
    {q:"Un buen lavado empieza con la separación de la ropa sucia, que se clasificará según:",o:["El grado de suciedad, tamaño y tipo de tejido.","El grado de suciedad, tamaño y color.","El grado de suciedad, nivel de deterioro y color.","El grado de suciedad, tipo de tejido y color."],a:3,translations:{eu:{q:"Garbiketa egokia egiteko, lehenik eta behin, arropa zikina bereizi behar da. Hala, arropa zikina honen arabera bereiziko da:",o:["Zikintasun-mailaren, neurriaren eta ehun motaren arabera.","Zikintasun-mailaren, neurriaren eta kolorearen arabera.","Zikintasun-mailaren, hondatze-mailaren eta kolorearen arabera.","Zikintasun-mailaren, ehun motaren eta kolorearen arabera."]}}},
    {q:"Durante la separación, la ropa es agrupada en lotes o fardos correspondientes a una fracción de la capacidad de la máquina:",o:["En general, 50% de sus capacidades de lavado.","Entre el 40% y 80% de sus capacidades de lavado.","Por encima del 50% de sus capacidades de lavado.","En general, 80% de sus capacidades de lavado."],a:3,translations:{eu:{q:"Arropa bereizteko orduan, lote edo fardeletan multzokatzen da. Zein izan behar du arropa-multzoen proportzioa, makinaren edukiera kontuan hartuta?",o:["Oro har, karga-edukieraren % 50.","Karga-edukieraren %40-80 artean.","Karga-edukieraren % 50etik gora.","Oro har, karga-edukieraren % 80."]}}},
    {q:"El ciclo para el lavado de ropa con suciedad más acusada comienza con:",o:["El remojado previo.","El prelavado.","La humectación.","La vaporización."],a:2,translations:{eu:{q:"Nola hasten da arropa zikinena garbitzeko zikloa?",o:["Aurretiko bustitzeaz.","Aurregarbiketaz.","Hezetzeaz.","Lurruntzeaz."]}}},
    {q:"En el procesamiento de la ropa hospitalaria, terminadas las operaciones de recepción, separación, pesaje y lavado:",o:["Toda el área debe ser ordenada.","Toda el área debe ser desinfectada y lavada.","Se hace control de stock.","Se realiza el cambio de turno."],a:1,translations:{eu:{q:"Ospitaleko arroparen prozesamenduan, behin arropa jaso, bereizi, pisatu eta garbitu ondoren…",o:["Eremu guztia ordenatu behar da.","Eremu guztia desinfektatu eta garbitu behar da.","Stockaren kontrola egiten da.","Txanda-aldaketa egiten da."]}}},
    {q:"Los principios asociados en el proceso del lavado son de orden:",o:["Físico.","Químico.","Físico y químico.","Electromecánico."],a:2,translations:{eu:{q:"Zer motatakoak dira garbiketa-prozesuarekin lotutako printzipioak?",o:["Fisikoak.","Kimikoak.","Fisikoak eta kimikoak.","Elektromekanikoak."]}}},
    {q:"Si el nivel del agua estuviera demasiado alto, durante los enjabonamientos, blanqueado y acidulación, puede ocurrir:",o:["Menor costo.","Menor necesidad de productos de lavado.","Permanencia de los residuos de productos.","Menor acción mecánica."],a:3,translations:{eu:{q:"Uraren maila altuegia izango balitz xaboitze-, zuritze- eta azidotze-faseetan, zer gerta daiteke?",o:["Kostua txikiagoa izango da.","Garbiketa-produktuen beharra txikiagoa izango da.","Produktuen hondakinak geratuko dira.","Ekintza mekanikoa txikiagoa izango da."]}}},
    {q:"En general, ¿Qué cantidad del agua utilizada en el lavado es agua tibia o caliente?",o:["Del 5 al 15%.","Del 15 al 25%.","Del 25 al 35%.","Del 35 al 45%."],a:1,translations:{eu:{q:"Oro har, garbiketan erabiltzen den uraren zer kantitate da epela edo beroa?",o:["% 5-15 artean.","% 15-25 artean.","% 25-35 artean.","% 35-45 artean."]}}},
    {q:"El tiempo es uno de los factores importantes del lavado. Señala la CORRECTA.",o:["Si el enjabonado es muy rápido será insuficiente para la actuación de los productos.","El enjuague es, en general, la operación más lenta del proceso.","El tiempo prolongado es más importante que la cantidad de enjabonado.","El tiempo utilizado para el lavado necesita de una media de 15 minutos."],a:0,translations:{eu:{q:"Denbora da garbiketaren faktore garrantzitsuenetako bat. Adierazi erantzun ZUZENA:",o:["Xaboitzea oso azkarra bada, ez da denbora nahikoa izango produktuek jarduteko.","Xaboia kentzekoa, oro har, prozesuko eragiketarik geldoena da.","Xaboitzea luzea izatea garrantzitsuagoa da kantitatea baino.","Garbitzeko denbora batez beste 15 minutukoa izan behar da."]}}},
    {q:"Cuando el jabón es colocado en demasiada cantidad, produce exceso de espuma…",o:["Facilitando el proceso de lavado.","Dificulta el enjuague.","Aumentando la concentración de la solución.","Mejora la acción mecánica."],a:1,translations:{eu:{q:"Zer egiten du xaboi-kantitate gehiegi jartzearen ondoriozko gehiegizko aparrak?",o:["Garbiketa-prozesua errazten du.","Irakuztea zailtzen du.","Soluzioaren kontzentrazioa handitzen du.","Ekintza mekanikoa hobetzen du."]}}},
    {q:"El blanqueador debe ser adicionado en la última enjabonada o en el primer enjuagado, para:",o:["Neutralizar los residuos alcalinos de la ropa.","Evitar que los efectos del cloro sean disminuidos por la presencia de materias orgánicas.","Economizar agua, tiempo y energía.","Evitar amarillear la ropa en el secado y el calandrado."],a:1,translations:{eu:{q:"Zertarako erantsi behar da zuritzailea azken xaboitze-prozesuan edo lehen irakuzketan?",o:["Arroparen hondakin alkalinoak neutralizatzeko.","Materia organikoek kloroaren efektuak gutxitzea saihesteko.","Ura, denbora eta energia aurrezteko.","Arropa lehortzean eta kalandratzean ez dadin horitu."]}}},
    {q:"La acidulación consiste en:",o:["Adicionar un producto ácido durante el blanqueado para bajar el pH y neutralizar los residuos alcalinos de la ropa.","Adicionar un producto ácido en el último aclarado para bajar el pH y neutralizar los residuos alcalinos de la ropa.","Adicionar un producto ácido en el último aclarado para subir el pH.","Adicionar en el último enjuague de determinados tejidos, un producto que contiene glicerina en su composición."],a:1,translations:{eu:{q:"Zer da azidifikatzea?",o:["Zuritzeko orduan produktu azido bat gehitzea, pHa jaisteko eta arroparen hondar alkalinoak neutralizatzeko.","Azken urberritzean produktu azido bat gehitzea, pHa jaisteko eta arroparen hondar alkalinoak neutralizatzeko.","Azken urberritzean produktu azido bat gehitzea, pHa areagotzeko.","Zenbait ehunen azken urberritzean, glizerina duen produktu bat gehitzea."]}}},
    {q:"Para conseguir una desinfección completa en el lavado de la ropa debe usarse:",o:["La temperatura de 65 a 75ºC durante 15 minutos.","La temperatura de 75 a 85 ºC, durante 10 minutos.","La temperatura de 85 a 95 ºC, durante 15 minutos.","La temperatura de 100 ºC, durante 10 minutos."],a:2,translations:{eu:{q:"Arropa garbitzeko orduan, nola lortzen da erabateko desinfekzioa?",o:["65-75 ºC-ko tenperatura jarrita 15 minutuz.","75-85 ºC-ko tenperatura jarrita 10 minutuz.","85-95 ºC-ko tenperatura jarrita 15 minutuz.","100 ºC-ko tenperatura jarrita 10 minutuz."]}}},
    {q:"La eliminación de las bacterias patógenas presentes en la ropa se consigue mediante la:",o:["Acidulación.","Clorodesinfección.","Vaporización.","Glicerinación."],a:1,translations:{eu:{q:"Nola lortzen da arropatik bakterio patogenoak deuseztatzea?",o:["Azidifikazioaren bidez.","Klorodesinfekzioaren bidez.","Baporizazioaren bidez.","Glizerinazioaren bidez."]}}},
    {q:"Señala la opción CORRECTA. En la eliminación de manchas.",o:["Herrumbre (amarillo-rojizo): a través de un prelavado en agua fría con sal.","Café: son quitadas con acidulantes.","Aceite o grasa: son disueltas por almidón, talco o arcilla blanca en polvo.","Tinta de escribir se quita con hielo."],a:2,translations:{eu:{q:"Adierazi aukera ZUZENA. Orbanak kentzea:",o:["Herdoila (hori-gorrixka): gatzarekin ur hotzean aurre garbitzea.","Kafea: azidotzaileekin kentzen dira.","Olioa edo koipea: almidoiaz, talkoaz edo buztin zuri hautsez disolbatzen dira.","Idazteko tinta izotzarekin kentzen da."]}}},
    {q:"Quitaremos las manchas de sangre:",o:["A través de un prelavado con agua caliente.","A través de un prelavado con agua fría.","Aplicando alcohol.","Con limón y sal en agua caliente."],a:1,translations:{eu:{q:"Nola kentzen dira odol-orbanak?",o:["Ur hotzarekin aurregarbiketa eginez.","Ur beroarekin aurregarbiketa eginez.","Alkoholaz.","Azido azetikoaz."]}}},
    {q:"Dentro del proceso de la ropa en el área limpia, la ropa seleccionada es distribuida para el secado en la siguiente proporción:",o:["35% para el calandrado, 35% para la secadora y 30% para el prensado o planchado.","45% para el calandrado, 35% para la secadora y 20% para el prensado o planchado.","55% para el calandrado, 35% para la secadora y 10% para el prensado o planchado.","70% para el calandrado, 25% para la secadora y 5% para el prensado o planchado."],a:3,translations:{eu:{q:"Arroparen prozesuaren barruan, gune garbian, arropa honela bereizten da lehortzera bidaltzeko:",o:["% 35 kalandrarako, % 35 lehorgailurako, eta % 30 prentsarako edo lisatzeko.","% 45 kalandrarako, % 35 lehorgailurako, eta % 20 prentsarako edo lisatzeko.","% 55 kalandrarako, % 35 lehorgailurako, eta % 10 prentsarako edo lisatzeko.","% 70 kalandrarako, % 25 lehorgailurako, eta % 5 prentsarako edo lisatzeko."]}}},
    {q:"El calandrado es una operación que seca y pisa al mismo tiempo",o:["Los uniformes.","Las piezas pesadas.","Las piezas pequeñas.","Las piezas de la ropa lisa."],a:3,translations:{eu:{q:"Zer lehortzen eta lisatzen du aldi berean kalandratuak?",o:["Uniformeak.","Pieza astunak.","Pieza txikiak.","Arropa lisoa."]}}},
    {q:"Señala la CORRECTA:",o:["En la centrifugación, por la eliminación del agua, se reduce un 80% del peso de la ropa.","En la centrifugadora la ropa se colocará en grandes pilas dentro de sacos de lona.","Ropas como colchas pesadas, piezas pequeñas y otras, son secadas en la secadora.","Las sábanas u colchas ligeras son pasadas por la prensa."],a:2,translations:{eu:{q:"Adierazi erantzun ZUZENA:",o:["Zentrifugazioan, ura kentzean, arroparen pisua % 80 gutxitzen da.","Zentrifugagailuan arropa olanazko zakuen barruan jartzen da, pila handietan.","Ohazal pisutsuak, pieza txikiak eta bestelakoak lehorgailuan lehortzen dira.","Maindireak edo ohazal arinak prentsatik pasatzen dira."]}}},
    {q:"¿Cuál de los siguientes es un elemento del área física, complementa el área limpia y canaliza el movimiento de toda la ropa del hospital?",o:["El ropero.","El vestidor.","La lavandería.","El vestuario."],a:0,translations:{eu:{q:"Erantzun hauetatik zein da eremu fisikoko elementu bat, gune garbiaren osagarri, eta ospitaleko arropa guztiaren mugimendua kanalizatzen duena?",o:["Arropategia.","Jantzigela.","Ikuztegia","Aldagela."]}}},
    {q:"La barrera de contaminación:",o:["Separa la lavandería en 3 áreas: lavado, secado y ropero.","Separa el área sucia y el área limpia.","Es eficiente si existe una lavadora de desinfección.","No puede tener visores."],a:1,translations:{eu:{q:"Kutsadura-hesia:",o:["Garbitegia hiru eremutan banatzen du: garbiketa, lehortzea eta arropa-tegia.","Eremu zikina eta eremu garbia bereizten ditu.","Eraginkorra da desinfekzio-garbigailu bat baldin badago.","Ezin du bisorerik (behatokirik) izan"]}}},
    {q:"Señala la INCORRECTA. Si el agua del lavado contiene sales de calcio (cal) se produce:",o:["Desperdicios de detergente.","La destrucción prematura de la ropa.","La disminución de las capacidades de absorción del tejido.","El ablandamiento y suavizado de la ropa."],a:3,translations:{eu:{q:"Markatu OKERRA dena. Garbiketa-urak kaltzio-gatzak (karea) baditu, hau gertatzen da:",o:["Detergente-galerak (detergentea alferrik galtzea).","Arropa goizegi hondatzea.","Ehunaren xurgatze-ahalmena gutxitzea.","Arropa biguntzea eta leuntzea."]}}},
    {q:"La caja de suspensión o de grosor con tela sirve para:",o:["Retener los hilos de la ropa.","Filtrar la cal del agua.","Suministrar productos desinfectantes.","Medir la temperatura"],a:0,translations:{eu:{q:"Oihaldun esegidura-kaxak edo lodiera-kaxak zertarako balio du?",o:["Arroparen hariak atxikitzeko.","Uraren karea iragazteko.","Produktu desinfektatzaileak hornitzeko.","Tenperatura neurtzeko."]}}},
    {q:"Señala la afirmación CORRECTA respecto de la recogida de la ropa sucia:",o:["Debe permanecer el mayor tiempo posible en la unidad.","El empleado debe usar guantes de caucho, máscara y gorro.","La ropa sucia se deposita directamente en el carro.","Utilizaremos el carro de la ropa limpia cuando se vacíe."],a:1,translations:{eu:{q:"Markatu arropa zikina biltzeari buruzko erantzun ZUZENA:",o:["Unitatean ahalik eta denbora gehien egon behar du.","Langileak kautxuzko eskularruak, maskarilla eta txanoa erabili behar ditu.","Arropa zikina zuzenean orga barruan uzten da.","Arropa garbiaren orga erabiliko dugu husten denean."]}}},
    {q:"En cada unidad de enfermería ¿Cuántas mudas se reciben para cada cama por día?",o:["Una y media por cama y día.","De una y media a dos mudas.","Dos mudas.","De dos a tres mudas."],a:1,translations:{eu:{q:"Erizaintzako unitate bakoitzean, zenbat arropa-aldaketa (muda) jasotzen dira ohe bakoitzeko eta eguneko?",o:["Bat eta erdi oheko eta eguneko.","Bat eta erdi eta bi arropa-aldaketa artean.","Bi arropa-aldaketa.","Bi eta hiru arropa-aldaketa artean."]}}},
    {q:"En la unidad de enfermería, la ropa de reserva:",o:["Debe constar en una lista de ropa.","Debe estar protegida con bolsa de tela.","Estará bien planchada y colgada en la percha.","No se repone hasta la mañana siguiente."],a:0,translations:{eu:{q:"Erizaintzako unitatean, erreserbako arropa:",o:["Arropa-zerrenda batean jaso behar da.","Oihalezko poltsa batekin babestuta egon behar du.","Ondo lisatuta eta eskoituran (pertxan) zintzilik egon behar du.","Ez da hurrengo goizera arte berritzen."]}}},
    {q:"Las mesas de planchado están recubiertas de:",o:["Una espuma siliconizada.","Una funda de nylon.","Una garnitura flexible y de una funda muletón.","Una tela de algodón."],a:2,translations:{eu:{q:"Lisatzeko mahaien gainaldea zerez estalita dago?",o:["Apar silikonizatuz.","Nylonezko estalki batez.","Estalki malgu batez eta muletoi batez.","Kotoizko tela batez."]}}},
    {q:"El planchado:",o:["Es un conjunto de operaciones diversas que tienen por objeto poner los artículos ya usados en un estado lo más próximo posible al que tenían de nuevos.","Es una operación que tiende a devolver a las ropas su aspecto, su textura y su calidad inicial.","Requiere destreza y entrenamiento práctico experto y la cuidadosa práctica de técnicas correctas.","Todas son correctas."],a:3,translations:{eu:{q:"Lisatzeari buruzko baieztapen hauetatik zein da ZUZENA?",o:["Zenbait jarduera biltzen dira ekintza horretan, eta helburua da artikulu erabiliak berriak zirenean zuten egoeraren ahalik antzekoenean uztea.","Arropari hasieran zuen itxura, ehundura eta kalitatea bueltatzen dion ekintza bat da.","Trebezia eta entrenamendu iaioa behar da lisatzeko, eta teknika zuzenak ondo zaindu behar dira.","Aurreko guztiak zuzenak dira."]}}},
    {q:"En el planchado, la recomendación en general es que el tiempo de vacío:",o:["Debe durar entre cinco y 15 segundos, y que la prenda debe sentirse siempre fría al tacto, antes de pasar a la siguiente operación.","NO debe ser menor de cinco segundos, y que la prenda debe sentirse siempre caliente al tacto, antes de pasar a la siguiente operación.","NO debe ser menor de cinco segundos, y que la prenda debe sentirse siempre fría al tacto, antes de pasar a la siguiente operación.","Debe durar entre cinco y 15 segundos, y que la prenda debe sentirse siempre caliente al tacto, antes de pasar a la siguiente operación."],a:2,translations:{eu:{q:"Lisaketan, hutsarteari dagokionez, zein da gomendioa, oro har?",o:["5 eta 15 segundo artean iraun behar du, eta arropa ukitzean beti hotza sentitu behar da hurrengo ekintzara pasatu aurretik.","Gutxienez 5 segundo iraun behar du, eta arropa ukitzean beti beroa sentitu behar da hurrengo ekintzara pasatu aurretik.","Gutxienez 5 segundo iraun behar du, eta arropa ukitzean beti hotza sentitu behar da hurrengo ekintzara pasatu aurretik.","5 eta 15 segundo artean iraun behar du, eta arropa ukitzean beti beroa sentitu behar da hurrengo ekintzara pasatu aurretik."]}}},
    {q:"De las siguientes fibras textiles, la que mejor soporta el calor es:",o:["Lino.","Lana.","Acrílico.","Poliamidas"],a:0,translations:{eu:{q:"Hauetako zein ehunek jasaten du ondoen beroa?",o:["Lihoak.","Artileak.","Akrilikoak.","Poliamidek."]}}},
    {q:"Señala la CORRECTA:",o:["Tanto el túnel de acabado como la cabina de acabado trabajan “continuamente”.","Tanto la cabina de acabado como el túnel de acabado trabajan “discontinuamente”.","Mientras el túnel de acabado trabaja “discontinuamente”, la cabina de acabado lo hace “continuamente”.","Mientras la cabina de acabado trabaja “discontinuamente”, el túnel de acabado lo hace “continuamente”."],a:3,translations:{eu:{q:"Adierazi erantzun ZUZENA:",o:["Akabera-tuneleko eta akabera-kabinako lana «etenik gabea» da.","Akabera-tuneleko eta akabera-kabinako lanak etenaldiak ditu.","Akabera-tuneleko lanak etenaldiak ditu, eta akabera-kabinako lana, berriz, «etenik gabea» da.","Akabera-kabinako lanak «etenaldiak ditu», eta akabera-tuneleko lana, berriz, «etenik gabea» da."]}}},
    {q:"La funda de tela que se hincha, para el planchado del cuerpo del pantalón, se denomina:",o:["Bacín.","Pan-topper.","Prensa.","Cojinete."],a:1,translations:{eu:{q:"Zer izen du galtzen gorputza lisatzen ari garenean puzten den telazko zorroak?",o:["Bazin.","Pan-topper.","Prentsa.","Kojinete."]}}},
    {q:"En el taller de planchado es importante:",o:["Tener todos los aparatos muy juntos.","Buena calefacción.","Un humidificador.","Buena aireación."],a:3,translations:{eu:{q:"Zer faktore da garrantzitsua lisatzeko lantegian?",o:["Gailu guztiak elkarrengandik oso gertu egotea.","Berokuntza ona izatea.","Hezegailua bat izatea.","Aireztapen ona izatea."]}}},
    {q:"El factor más importante para obtener un buen planchado es:",o:["La humedad.","La presión.","El calor.","El descenso brusco de la temperatura del tejido después del calentamiento."],a:2,translations:{eu:{q:"Zein da ondo lisatzeko faktore GARRANTZITSUENA?",o:["Hezetasuna.","Presioa.","Beroa.","Ehunaren tenperatura bat-batean jaistea, beroaren eraginpean egon ondoren."]}}},
    {q:"La excesiva vaporización en el proceso del planchado puede producir:",o:["Fatiga al operador.","Disolución del tejido.","Holgura en tejidos de algodón.","Endurecimiento del tejido."],a:0,translations:{eu:{q:"Lisatze-prozesuan lurrun gehiegi erabiltzeak zer eragin dezake?",o:["Operadorearen nekea.","Ehuna desegitea.","Kotoizko ehunen zabaltzea.","Ehuna gogortzea."]}}},
    {q:"En el planchado:",o:["La operación de vacío es menos importante que la vaporización.","El vacío es el que da consistencia a la pieza.","En la operación de vacío será suficiente un ligero toque de pedal.","La recomendación en general es que el tiempo de vacío NO debe ser menor de quince segundos."],a:1,translations:{eu:{q:"Lisatzean:",o:["Hutseko eragiketa ez da lurruntzea bezain garrantzitsua.","Hutsak sendotasuna ematen dio piezari.","Hutseko eragiketarako pedal ukitu txiki bat nahikoa izango da.","Oro har gomendatzen da hutseko eragiketa hamabost segundotik beherakoa izatea."]}}},
    {q:"El poliéster soporta una temperatura hasta:",o:["110ºc.","150ºc.","200ºc.","245ºc."],a:1,translations:{eu:{q:"Zer tenperatura jasaten du gehienez poliesterrak?",o:["110ºC.","150ºC.","200ºC.","245ºC."]}}},
    {q:"La prensa universal de planchado:",o:["Lleva accesorios diversos como el soporte para la plancha.","Tiene un ciclo de 4 tiempos.","Se compone de dos platos recubiertos.","Puede ser con bancada de forma rectangular o contorneada."],a:2,translations:{eu:{q:"Lisatzeko prentsa unibertsala:",o:["Zenbait osagarri ditu, hala nola lisaburdinerako euskarria.","Lau denborako zikloa du.","Bi plater estalik osatzen dute.","Bankada laukizuzena edo biribildua izan dezake"]}}},
    {q:"Cualidades que debe tener el revestimiento de tela de la prensa universal de planchado:",o:["Ser lisa, para NO dejar marcas en los tejidos finos.","Ser impermeable al vapor.","Ser de seda natural.","Ser suficientemente rígida."],a:0,translations:{eu:{q:"Zer ezaugarri izan behar ditu lisatzeko prentsa unibertsalaren oihalezko estaldurak?",o:["Lisoa izan behar da, ehun finetan arrastorik ez uzteko.","Lurrunarekiko iragazgaitza izan behar da.","Zeta naturalezkoa izan behar da.","Nahiko zurruna izan behar da."]}}},
    {q:"El sistema de aspiración de la prensa universal se encuentra:",o:["En el plato inferior.","En el plato superior.","En ambos platos.","La prensa universal no tiene este sistema."],a:0,translations:{eu:{q:"Non dago prentsa unibertsalaren xurgapen-sistema?",o:["Beheko platerean.","Goiko platerean.","Bi plateretan.","Prentsa unibertsalak ez dauka halako sistemarik."]}}},
    {q:"¿Cuál NO es un tipo de mesa de planchado?",o:["Mesa calentadora.","Mesa aspirante.","Mesa vaporizante.","Mesa irradiante."],a:3,translations:{eu:{q:"Zein EZ da lisatzeko mahai mota bat?",o:["Berotzeko mahaia.","Xurgatze-mahaia.","Mahai lurruneztatzailea.","Mahai irradiatzailea."]}}},
    {q:"El recubrimiento de la mesa de planchar:",o:["Debe ser impermeable.","Debe ser duro y compacto.","Necesita “elasticidad”.","Consiste en una funda de espuma siliconizada."],a:2,translations:{eu:{q:"Nolakoa da lisatzeko mahaiaren estaldura?",o:["Iragazgaitza izan behar da.","Gogorra eta trinkoa izan behar da.","“Elastikotasuna” behar da.","Apar silikonizatuzko zorro bat da."]}}},
    {q:"Las cabinas y túneles de acabado del proceso de planchado:",o:["Permiten tratar simultáneamente más de 25 prendas.","Eliminan completamente las arrugas de uso de las entrepiernas de pantalones.","Ambos trabajan continuamente.","Interesan especialmente para artículos de punto sintéticos o naturales."],a:3,translations:{eu:{q:"Lisatze-prozesuaren akabera-kabinak eta -tunelak:",o:["Aldi berean 25 jantzi baino gehiago tratatzeko aukera ematen dute.","Erabilera-zimurrak erabat kentzen dituzte hankatartetik.","Etengabe ari dira lanean.","Interesgarriak dira bereziki puntu sintetikozko edo naturalezko jantzietarako."]}}},
    {q:"En el planchado, el equipo base de servicio de acabado comprende:",o:["La prensa universal y el túnel de acabado.","La prensa universal y la mesa de planchado.","La prensa universal y la cabina.","La prensa universal y el pan-topper"],a:1,translations:{eu:{q:"Zer osagarri ditu lisatzeko akabera-zerbitzuko oinarrizko ekipoak?",o:["Prentsa unibertsala eta akabera-tunela.","Prentsa unibertsala eta lisatzeko mahaia.","Prentsa unibertsala eta kabina.","Prentsa unibertsala eta Pan Topper-a."]}}},
    {q:"Es un aparato con forma de armario equipado con un sistema de vaporización y otro de circulación de aire caliente:",o:["Cabina de acabado.","Mesa de planchar.","Vaporizador.","Prensa universal."],a:0,translations:{eu:{q:"Armairu formako aparatu bat da, lurruneztatze-sistema bat eta aire beroko zirkulazio-sistema bat dituena:",o:["Akabera-kabina.","Lisatzeko mahaia.","Lurruneztagailua.","Prentsa unibertsala."]}}},
    {q:"Señala la opción INCORRECTA sobre la operación de vacío en el planchado.",o:["Esta operación es más importante que la vaporización.","Tras vaporizar, antes de pasar a la siguiente operación, la prenda debe sentirse siempre caliente al tacto.","El tiempo de vacío NO debe ser menor de 5 segundos.","Es preferible sobrevaporizar que vaporizar de menos."],a:1,translations:{eu:{q:"Adierazi aukera OKERRA lisaketako huts-eragiketari buruz:",o:["Eragiketa hau lurruneztatzea baino garrantzitsuagoa da.","Lurruneztatzearen ondoren, hurrengo eragiketara igaro aurretik, jantzia ukitzean bero sentitu behar da beti.","Huts-denbora ezin da 5 segundotik beherakoa izan.","Hobe da lurruneztatze gehiegi egitea, gutxiegi baino."]}}},
    {q:"¿Dónde se suele ejecutar el planchado de la chaqueta?",o:["Prensa universal.","Cabina de acabado.","Maniquí.","Todas son correctas."],a:3,translations:{eu:{q:"Non lisatzen dira jakak?",o:["Prentsa unibertsalean.","Akabera-kabinan.","Manikian.","Aurreko erantzun guztiak zuzenak dira."]}}},
    {q:"Con la ropa que pasa por el túnel de acabado es posible:",o:["Borrar más o menos todos los pliegues.","Rehacer los pliegues de confección.","Ahuecar el tejido mejorando el aspecto y la caída de la prenda.","a) y c) son correctas."],a:3,translations:{eu:{q:"Arropa akabera-tunelean sartuta lortzen da:",o:["Tolestura guztiak ezabatzea, gutxi gorabehera.","Josteko tolesturak berregitea.","Ehuna harrotzea, eta jantziaren itxura eta erorkera hobetzea.","a) eta c) zuzenak dira."]}}},
    {q:"En prendas ligeras (blusas):",o:["El vaporizado debe durar 1-2 segundos y el vacío 5 segundos.","El vaporizado debe durar 8 segundos y el vacío 16-17 segundos.","El vaporizado debe durar 5-6 segundos y el vacío 10-12 segundos.","El vaporizado debe durar 4 segundos y el vacío 8-9 segundos."],a:0,translations:{eu:{q:"Jantzi arinen kasuan (blusak):",o:["Lurruneztatzeak 1-2 segundo iraun behar du, eta hutsak 5 segundo.","Lurruneztatzeak 8 segundo iraun behar du, eta hutsak 16-17 segundo.","Lurruneztatzeak 5-6 segundo iraun behar du, eta hutsak 10-12 segundo.","Lurruneztatzeak 4 segundo iraun behar du, eta hutsak 8-9 segundo."]}}},
    {q:"¿Cuál de las siguientes prendas NO se deben planchar?",o:["Prendas de clorofibra.","Prendas de lino.","Prendas de seda.","Prendas de poliéster."],a:0,translations:{eu:{q:"Ondorengo jantzietatik, zein EZ da lisatu behar?",o:["Klorozuntzezko jantziak.","Lihozko jantziak.","Zetazko jantziak.","Poliesterrezko jantziak."]}}},
    {q:"En el planchado, la temperatura de seguridad de la lana es de:",o:["230 ºC.","150 ºC.","180 ºC","215 ºC."],a:1,translations:{eu:{q:"Lisatzean, zein da artilearen segurtasun-tenperatura?",o:["230 ºC.","150 ºC.","180 ºC","215 ºC."]}}},
    {q:"¿Cuál es una causa principal del pegado de componentes accionados por aire?",o:["Presión de vapor demasiado alta.","Mala calidad del aire del compresor: aire caliente, húmedo o con lubricación incorrecta.","Exceso de vacío en la prensa.","Temperatura baja del plato de planchado."],a:1,translations:{eu:{q:"Zein da airez eragindako osagaiak itsastearen arrazoi nagusietako bat?",o:["Lurrun-presio altuegia.","Konpresoreko airearen kalitate txarra: aire beroa, hezea edo lubrifikazio desegokiarekin.","Gehiegizko hutsa prentsan.","Lisatzeko plateraren tenperatura baxua."]}}},
    {q:"¿Cuál es una medida CORRECTA para evitar deformaciones y alargamientos en las prendas?",o:["Usar siempre el mismo ciclo de temperatura y duración.","Evitar clasificar las prendas por tipo.","Clasificar los artículos por categoría y adaptar el ciclo a cada uno.","Usar cualquier tipo de percha disponible."],a:2,translations:{eu:{q:"Zein da jantzietan deformazioak eta luzapenak saihesteko neurri ZUZENA?",o:["Beti tenperatura- eta iraupen-ziklo bera erabili.","Jantziak ez dira motaren arabera sailkatu behar.","Artikuluak kategoriaren arabera sailkatu eta egokitu zikloa.bakoitzari.","Erabilgarri dagoen edozein esekigailu-mota erabili."]}}},
    {q:"Al planchar un pantalón en prensa universal, ¿por qué es importante controlar el paso del calor al frío?",o:["Porque evita que el tejido se humedezca demasiado.","Porque fija el tejido en la forma deseada, manteniendo los pliegues correctamente.","Porque acelera el secado de la prenda sin afectar la forma.","Porque reduce la presión necesaria sobre la prenda."],a:1,translations:{eu:{q:"Galtzak prentsa unibertsalean lisatzean, zergatik da garrantzitsua berotik hotzerako bidea kontrolatzea?",o:["Ehuna gehiegi hezetzea saihesten duelako.","Ehuna nahi den moduan finkatzen duelako, tolesturak behar bezala mantenduz.","Jantziaren lehorketa azkartzen duelako formari eragin gabe.","Arroparen gaineko beharrezko presioa murrizten duelako."]}}},
    {q:"¿Cuáles son las dos fases del funcionamiento de los túneles de acabado?",o:["Lavado y centrifugado.","Vaporización y secado.","Enfriamiento y doblado.","Compresión y sellado."],a:1,translations:{eu:{q:"Zein dira akabera-tunelen funtzionamenduaren bi faseak?",o:["Garbitzea eta zentrifugatzea.","Lurruntzea eta lehortzea.","Hoztea eta tolestea.","Konpresioa eta zigilatzea."]}}},
    {q:"En el planchado, la temperatura de seguridad de la acrílica es de:",o:["75-100 ºC.","150- 2175 ºC.","180-200 ºC.","200-215 ºC."],a:0,translations:{eu:{q:"Lisatzean, akrilikoaren segurtasun-tenperatura hau da:",o:["75-100 ºC.","150- 2175 ºC.","180-200 ºC.","200-215 ºC."]}}},
    {q:"¿Cuáles son las dos grandes fases del planchado del pantalón?",o:["Lavado y secado.","Vaporización y doblado.","Planchado del bacín hasta la cintura y planchado de las piernas.","Marcado de bolsillos y costuras laterales."],a:2,translations:{eu:{q:"Zein dira galtzak lisatzeko bi fase nagusiak?",o:["Garbitzea eta lehortzea.","Lurruntzea eta tolestea.","Bakina gerriraino lisatzea eta zangoak lisatzea.","Poltsikoak eta alboetako josturak markatzea."]}}},
    {q:"Se usa para enfriar y secar totalmente el artículo, de modo que los pliegues queden bien marcados.",o:["El lavado.","El vacío.","La presión.","El vapor."],a:1,translations:{eu:{q:"Artikulua erabat hozteko eta lehortzeko erabiltzen da, tolesturak ongi markatuta gera daitezen.",o:["Garbitzea.","Hutsa.","Presioa.","Lurruna."]}}},
    {q:"La prensa de doble pierna…",o:["Es una prensa corta en la cual se efectúa el planchado del bacín en 5 o 6 operaciones.","Es una prensa cuya plancha inferior más plana que la de una prensa universal.","Tiene una escotadura en el extremo o en una esquina.","Permite el prensado de las dos piernas al mismo tiempo."],a:3,translations:{eu:{q:"Hanka biko prensa…",o:["Prentsa laburra da, eta bakina 5 edo 6 eragiketatan lisatzen da.","Beheko plantxa prentsa unibertsalekoa baino lauagoa duen prentsa da.","Muxarradura bat dauka muturrean edo izkina batean.","Bi hankak aldi berean prentsatzeko aukera ematen du."]}}},
    {q:"¿En qué tipo de artículos son más frecuentes los alargamientos?",o:["En prendas de algodón ligero.","En artículos de seda natural.","En artículos de fibras acrílicas y, a veces, de lana.","En prendas de lino corto."],a:2,translations:{eu:{q:"Zein artikulu motatan dira ohikoenak luzapenak?",o:["Kotoi arineko arropetan.","Zetazko artikulu naturaletan.","Zuntz akrilikozko artikuluetan eta, batzuetan, artilezkoetan.","Liho motzeko jantzietan."]}}}
  ]
});
